CREATE PROCEDURE [dbo].[DataBase_TransactsInitialization]

AS
BEGIN

set nocount on;
    declare @trancount int;
    set @trancount = @@trancount;
    begin try
        if @trancount = 0
            begin transaction
        else
            save transaction DataBase_TransactsInitialization;
----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
EXEC sys.sp_msforeachtable 'ALTER TABLE ? NOCHECK CONSTRAINT ALL'

------ Remove From Details And Related Tables First ----------------------
DECLARE  @MainTable nvarchar(max) 
declare @t table (SubTable nvarchar(max))
DECLARE @SubstrSQL Varchar(MAX) = '';

DECLARE cur CURSOR 
FOR SELECT TableName from SystemPage where /*IsMasterFile!=1 and*/ IsTransaction=1 and TableName is not null;
OPEN cur;
FETCH NEXT FROM cur INTO 
    @MainTable  
WHILE @@FETCH_STATUS = 0
    BEGIN
insert into @t (SubTable)
(select OBJECT_NAME(sys.foreign_keys.parent_object_id) 'SubTable'
 FROM sys.foreign_keys INNER JOIN sys.foreign_key_columns  
      ON OBJECT_ID = sys.foreign_key_columns .constraint_object_id WHERE sys.foreign_keys.referenced_object_id = OBJECT_ID( @MainTable))
		FETCH NEXT FROM cur INTO 
		 @MainTable 
    END;
SELECT @SubstrSQL = @SubstrSQL + 'Delete From ' + quotename(schema_Name(schema_id)) + '.' + QUOTENAME(name) + '; '
  FROM sys.tables 
  WHERE type_desc = 'USER_TABLE'
  AND name IN (select t.SubTable from @t t)
  ORDER BY name;
  execute(@SubstrSQL)
CLOSE cur;
DEALLOCATE cur;
---------------------------------------------------------------------------------
DECLARE @strSQL Varchar(MAX) = '';
SELECT @strSQL = @strSQL + 'Delete From ' + quotename(schema_Name(schema_id)) + '.' + QUOTENAME(name) + '; '
  FROM sys.tables 
  WHERE type_desc = 'USER_TABLE'
  AND name IN (select TableName from SystemPage where /*IsMasterFile!=1 and*/ IsTransaction=1 and TableName is not null)
  ORDER BY name;
  execute(@strSQL)

  EXEC sys.sp_MSForEachTable 'ALTER TABLE ? CHECK CONSTRAINT ALL'
----------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
lbexit:
        if @trancount = 0
            commit;
    end try
    begin catch
        declare @error int, @message varchar(4000), @xstate int;
        select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        if @xstate = -1
            rollback;
        if @xstate = 1 and @trancount = 0
            rollback
        if @xstate = 1 and @trancount > 0
            rollback transaction DataBase_TransactsInitialization;

        raiserror ('DataBase_TransactsInitialization: %d: %s', 16, 1, @error, @message ) ;
    end catch
end

