CREATE PROCEDURE [dbo].[GetDocNum]
	-- Add the parameters for the stored procedure here
@SourceId int,
@SourcePageId int
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
DECLARE @IntVariable int;  
DECLARE @SQLString nvarchar(500);  
DECLARE @ParmDefinition nvarchar(500);  
DECLARE @max_title varchar(100);  
declare @t nvarchar(100)=(select TableName from SystemPage where Id=@SourcePageId)

SET @IntVariable = @SourceId;  
SET @SQLString = N'SELECT @max_titleOUT =DocumentNumber
   FROM '+@t + 
   ' WHERE id = @level';  
SET @ParmDefinition = N'@level int, @max_titleOUT varchar(100) OUTPUT';  

EXECUTE sp_executesql @SQLString, @ParmDefinition, @level = @IntVariable, @max_titleOUT=@max_title OUTPUT;  
return @max_title;  
END

CREATE PROCEDURE dbo.GetNextDocumentNumberSafe
    @TableName NVARCHAR(100),
    @DepartmentId INT,
    @VoucherDate DATETIME,
    @DocumentNumber NVARCHAR(MAX) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- DocumentsCoding variables
    DECLARE @NoOfDigit INT;
    DECLARE @CodingTypeId INT;
    DECLARE @IsZerosFills BIT;
    DECLARE @YearFormat INT;
    DECLARE @IsExistInDocumentsCoding BIT = 0;

    -- Date formatting
    DECLARE @MonthFormat NVARCHAR(2) = RIGHT('0' + CONVERT(NVARCHAR(2), MONTH(@VoucherDate)), 2);
    DECLARE @YearFormatString NVARCHAR(4) = CONVERT(NVARCHAR(4), YEAR(@VoucherDate));

    -- Department Code
    DECLARE @DepartmentCode NVARCHAR(10) =
    (
        SELECT CONVERT(NVARCHAR(10), Code)
        FROM Department
        WHERE IsActive = 1 AND IsDeleted = 0 AND Id = @DepartmentId
    );

    -- Pad department code with leading zero if needed
    IF (TRY_CONVERT(INT, @DepartmentCode) < 10)
        SET @DepartmentCode = '0' + @DepartmentCode;

    -- Get DocumentsCoding settings
    DECLARE @DocumentCodingCode NVARCHAR(50) =
    (
        SELECT TOP(1) Code
        FROM DocumentsCoding
        WHERE IsActive = 1 AND IsDeleted = 0 AND DepartmentId = @DepartmentId
    );

    IF (@DocumentCodingCode IS NULL)
    BEGIN
        -- Try AllDepartments coding
        SET @DocumentCodingCode =
        (
            SELECT TOP(1) Code
            FROM DocumentsCoding
            WHERE IsActive = 1 AND IsDeleted = 0 AND AllDepartments = 1
        );

        IF (@DocumentCodingCode IS NULL)
        BEGIN
            SET @IsExistInDocumentsCoding = 0;
            SET @NoOfDigit = 4;
            SET @CodingTypeId = 1;
            SET @IsZerosFills = 1;
            SET @YearFormat = 4;
        END
        ELSE
        BEGIN
            SELECT TOP(1)
                @NoOfDigit = DigitsNo,
                @CodingTypeId = CodingTypeId,
                @IsZerosFills = IsZerosFills,
                @YearFormat = YearFormat
            FROM DocumentsCoding
            WHERE IsActive = 1 AND IsDeleted = 0 AND AllDepartments = 1;

            SET @IsExistInDocumentsCoding = 1;
        END
    END
    ELSE
    BEGIN
        SELECT TOP(1)
            @NoOfDigit = DigitsNo,
            @CodingTypeId = CodingTypeId,
            @IsZerosFills = IsZerosFills,
            @YearFormat = YearFormat
        FROM DocumentsCoding
        WHERE IsActive = 1 AND IsDeleted = 0 AND DepartmentId = @DepartmentId;

        SET @IsExistInDocumentsCoding = 1;
    END

    -- Apply defaults
    IF ISNULL(@NoOfDigit, 0) = 0 SET @NoOfDigit = 4;
    IF @IsZerosFills IS NULL SET @IsZerosFills = 1;
    IF @CodingTypeId IS NULL SET @CodingTypeId = 1;
    IF @YearFormat IS NULL SET @YearFormat = 4;

    -- Format year token
    DECLARE @YearToken NVARCHAR(4);
    IF (@YearFormat = 2)
        SET @YearToken = RIGHT(@YearFormatString, 2);
    ELSE
        SET @YearToken = @YearFormatString;

    -- Build prefix based on coding type
    DECLARE @PrefixMonth NVARCHAR(100) = @DepartmentCode + N'-' + @YearToken + N'-' + @MonthFormat + N'-';
    DECLARE @PrefixYear NVARCHAR(100) = @DepartmentCode + N'-' + @YearToken + N'-';

    DECLARE @Prefix NVARCHAR(100) =
        CASE
            WHEN @CodingTypeId = 3 THEN @PrefixYear
            ELSE @PrefixMonth
        END;

    /* ===================== CRITICAL SECTION: AppLock ===================== */

    DECLARE @LockName NVARCHAR(200) = @TableName + N':' + @Prefix;
    DECLARE @lockResult INT;

    EXEC @lockResult = sys.sp_getapplock
        @Resource = @LockName,
        @LockMode = 'Exclusive',
        @LockOwner = 'Transaction',
        @LockTimeout = 15000;  -- 15 seconds timeout

    IF @lockResult < 0
    BEGIN
        RAISERROR(N'GetNextDocumentNumberSafe: Cannot acquire document number lock for %s', 16, 1, @TableName);
        RETURN;
    END

    /* ===================== Get Next Serial Number ===================== */

    DECLARE @NextSerial INT;
    DECLARE @SQL NVARCHAR(MAX);

    -- Build dynamic SQL based on table name
    IF @TableName = 'JournalEntry'
    BEGIN
        ;WITH L AS
        (
            SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(DocumentNumber, '-', '.'), 1)) AS Serial
            FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
            WHERE DepartmentId = @DepartmentId
              AND IsActive = 1
              AND IsDeleted = 0
              AND DocumentNumber LIKE @Prefix + N'%'
        )
        SELECT @NextSerial = ISNULL(MAX(Serial), 0) + 1
        FROM L;
    END
    ELSE IF @TableName = 'CashIssueVoucher'
    BEGIN
        ;WITH L AS
        (
            SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(DocumentNumber, '-', '.'), 1)) AS Serial
            FROM dbo.CashIssueVoucher WITH (UPDLOCK, HOLDLOCK)
            WHERE DepartmentId = @DepartmentId
              AND IsActive = 1
              AND IsDeleted = 0
              AND DocumentNumber LIKE @Prefix + N'%'
        )
        SELECT @NextSerial = ISNULL(MAX(Serial), 0) + 1
        FROM L;
    END
    ELSE IF @TableName = 'CashReceiptVoucher'
    BEGIN
        ;WITH L AS
        (
            SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(DocumentNumber, '-', '.'), 1)) AS Serial
            FROM dbo.CashReceiptVoucher WITH (UPDLOCK, HOLDLOCK)
            WHERE DepartmentId = @DepartmentId
              AND IsActive = 1
              AND IsDeleted = 0
              AND DocumentNumber LIKE @Prefix + N'%'
        )
        SELECT @NextSerial = ISNULL(MAX(Serial), 0) + 1
        FROM L;
    END
    ELSE IF @TableName = 'PropertyDueBatch'
    BEGIN
        ;WITH L AS
        (
            SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(DocumentNumber, '-', '.'), 1)) AS Serial
            FROM dbo.PropertyDueBatch WITH (UPDLOCK, HOLDLOCK)
            WHERE DepartmentId = @DepartmentId
              AND IsDeleted = 0
              AND DocumentNumber LIKE @Prefix + N'%'
        )
        SELECT @NextSerial = ISNULL(MAX(Serial), 0) + 1
        FROM L;
    END
    ELSE IF @TableName = 'PropertyContractTermination'
    BEGIN
        ;WITH L AS
        (
            SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(DocumentNumber, '-', '.'), 1)) AS Serial
            FROM dbo.PropertyContractTermination WITH (UPDLOCK, HOLDLOCK)
            WHERE DepartmentId = @DepartmentId
              AND IsDeleted = 0
              AND DocumentNumber LIKE @Prefix + N'%'
        )
        SELECT @NextSerial = ISNULL(MAX(Serial), 0) + 1
        FROM L;
    END
    ELSE IF @TableName = 'PropertyBillRegisteration'
    BEGIN
        ;WITH L AS
        (
            SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(TransactionNumber, '-', '.'), 1)) AS Serial
            FROM dbo.PropertyBillRegisteration WITH (UPDLOCK, HOLDLOCK)
            WHERE TransactionNumber LIKE @Prefix + N'%'
        )
        SELECT @NextSerial = ISNULL(MAX(Serial), 0) + 1
        FROM L;
    END
    ELSE
    BEGIN
        -- Default fallback for unknown tables
        SET @NextSerial = 1;
    END

    /* ===================== Format Serial Number ===================== */

    DECLARE @SerialStr NVARCHAR(20);

    IF @IsZerosFills = 1
        SET @SerialStr = RIGHT(REPLICATE('0', @NoOfDigit) + CONVERT(NVARCHAR(20), @NextSerial), @NoOfDigit);
    ELSE
        SET @SerialStr = CONVERT(NVARCHAR(20), @NextSerial);

    /* ===================== Build Final Document Number ===================== */

    IF @IsExistInDocumentsCoding = 1
        SET @DocumentNumber = @Prefix + @SerialStr;
    ELSE
        SET @DocumentNumber = @SerialStr;  -- Old coding fallback

END

CREATE PROCEDURE [dbo].[GetServicePriceForZeroPoint]
@WrittenPrice money,
@ServiceId int,
@AllowDiscount bit
as
Declare @ServiceCompanyPercentage money=(select isnull(CompanyPercentage,0) from [dbo].[Service] where Id=@ServiceId)

Declare @Price money=@WrittenPrice
if (@AllowDiscount=1 and @ServiceCompanyPercentage!=0 and @ServiceCompanyPercentage!=100)
begin
set @Price=@Price/2
end

select isnull(@Price,0) as ServicePrice

