	 @FieldsCodingId   int   ,
	 @NotIncludeValueAddedTax   bit   ,
	 @TaxPercentage   float   ,
	 @Barcode1  nvarchar(max)  ,
	 @Price1 money  ,
	 @ItemUnitId1  int  ,
	 @Equivalent1 int  ,
	 @CustomerGroupId1 int  ,
