	 @Barcode3  nvarchar(max) ,
	 @Price3 money  ,
	 @ItemUnitId3  int  ,
	 @Equivalent3 int  ,
	 @CustomerGroupId3 int  


OPEN ItemCur
IF @@CURSOR_ROWS > 0
 BEGIN 
 FETCH NEXT FROM ItemCur INTO 
     @Id ,
	 @Code ,
	 @ArName ,
	 @EnName ,
	 @KrName ,
	 @OrderLimit ,
	 @ItemGroupId ,
	 @ItemTypeId ,
