	 )
 set @MaxItemId=(select max(Id) from Item)
 if(@Barcode1 is not null and @Price1  is not null and @ItemUnitId1  is not null and @Equivalent1  is not null and @CustomerGroupId1  is not null )
	 begin
 insert into ItemPrice (
            [Barcode]
           ,[ItemId]
           ,[Price]
		   ,[ItemUnitId]
           ,[Equivalent]
           ,[CustomerGroupId]
           ,[IsDefault]
           ,[IsActive]
