		   )
 values (@Barcode1, @MaxItemId,  @Price1 ,@ItemUnitId1 ,@Equivalent1 ,@CustomerGroupId1 ,1,1,0)
 end
else if(@Barcode2  is not null and @Price2  is not null and @ItemUnitId2  is not null and @Equivalent2  is not null and @CustomerGroupId2  is not null)
	 begin 
	  insert into ItemPrice (
