		   )
 values (@Barcode2, @MaxItemId,  @Price2 ,@ItemUnitId2 ,@Equivalent2 ,@CustomerGroupId2 ,1,1,0)
	 end
	 else if(@Barcode3  is not null and @Price3  is not null and @ItemUnitId3  is not null and @Equivalent3  is not null and @CustomerGroupId3 is not null )
	 begin 
