CREATE PROCEDURE [dbo].[InventoryVoucher_Adjustment]
	-- Add the parameters for the stored procedure here
	@Id int
as
begin
set nocount on;
    declare @trancount int;
    set @trancount = @@trancount;
    begin try
        if @trancount = 0
            begin transaction
        else
            save transaction InventoryVoucher_Adjustment;

    -- Insert statements for procedure here
	declare @BranchId [int],
	@WarehouseId [int] ,
	@DepartmentId [int] ,
	@VoucherDate [datetime] ,
	@VendorOrCustomerId [int] ,
	@CurrencyId [int] ,
	@CurrencyEquivalent [float] ,
	@Total [money] ,
	@TotalItemsDiscount [money] ,
	@SalesTaxes [money] ,
	@TotalAfterTaxes [money] ,
	@VoucherDiscountValue [money] ,
	@VoucherDiscountPercentage [float] ,
	@NetTotal [money] ,
	@Paid [money] ,
	@ValidityPeriod [float] ,
	@DeliveryPeriod [float] ,
	@CostPriceId [int] ,
	@CurrentQuantity [float] ,
	@DestinationWarehouseId [int] ,
	@TotalCostPrice [money] ,
	@TotalItemDirectExpenses [money] ,
	@IsDelivered [bit] ,
	@IsAccepted [bit] ,
	@IsLinked [bit] ,
	@IsCompleted [bit] ,
	@IsPosted [bit] ,
	@UserId [int] ,
	@IsActive [bit] ,
	@IsDeleted [bit] ,
	@AutoCreated [bit] ,
	@Notes [nvarchar](max) ,
	@Image [nvarchar](max) ,
	@UpdatedId [int],
	@AdjustmentonEmployeeReceivable bit

	select @BranchId=BranchId ,
	@WarehouseId =WarehouseId ,
	@DepartmentId =DepartmentId ,
	@VoucherDate  =VoucherDate,
	@VendorOrCustomerId =VendorOrCustomerId ,
	@CurrencyId  =CurrencyId,
	@CurrencyEquivalent =CurrencyEquivalent,
	@Total =Total ,
	@TotalItemsDiscount =TotalItemDirectExpenses ,
	@SalesTaxes  =SalesTaxes,
	@TotalAfterTaxes=TotalAfterTaxes  ,
	@VoucherDiscountValue =VoucherDiscountValue ,
	@VoucherDiscountPercentage  =VoucherDiscountPercentage,
	@NetTotal =NetTotal ,
	@Paid=Paid  ,
	@ValidityPeriod =ValidityPeriod ,
	@DeliveryPeriod =DeliveryPeriod ,
	@CostPriceId =CostPriceId ,
	@CurrentQuantity =CurrentQuantity ,
	@DestinationWarehouseId =DestinationWarehouseId ,
	@TotalCostPrice =TotalCostPrice ,
	@TotalItemDirectExpenses =TotalItemDirectExpenses ,
	@IsDelivered=IsDelivered  ,
	@IsAccepted =IsAccepted ,
	@IsLinked =IsLinked ,
	@IsCompleted =IsCompleted ,
	@IsPosted=0  ,
	@UserId =UserId ,
	@IsActive=IsActive  ,
	@IsDeleted=0  ,
	@AutoCreated =AutoCreated ,
	@Notes  =Notes,
	@Image =Image ,
	@UpdatedId =UpdatedId,
	@AdjustmentonEmployeeReceivable=AdjustmentonEmployeeReceivable
	from InventoryVoucher where Id=@Id

	declare @SystemPageId int=(select Id from SystemPage where ControllerName='InventoryVoucher')

	update InventoryVoucher set IsCompleted=1 where Id=@Id

if exists (select id from InventoryVoucherDetails where MainDocId=@Id and Qty<QtyOnSystem)
begin
		declare @StockIssueDetailsXml nvarchar(max)=(SELECT [MainDocId]
			,[ItemId]
           ,QtyOnSystem-[Qty] [Qty]
           ,[ItemPriceId]
           ,[Price]
           ,[ItemUnitId]
           ,[UnitEquivalent]
           ,[CurrencyId]
           ,[CurrencyEquivalent]
           ,[DiscountValue]
           ,[DiscountPerc]
           ,[WareHouseId]
           ,[WarrantyPeriod]
           ,[WarrantyStart]
           ,[ExpireDate]
           ,[PatchId]
           ,@SystemPageId [SystemPageId]
           ,@Id [SelectedId]
           ,[RemainQty]
           ,[CostPrice] --[dbo].[Item_AvgCost](ItemId, @DepartmentId) [CostPrice]
           ,[ItemDirectExpenses]
           ,[IsDeleted]
           ,[UpdatedId] from InventoryVoucherDetails where MainDocId=@Id and Qty<QtyOnSystem for xml raw ('Details'), root ('DocumentElement'), ELEMENTS)

	select @TotalCostPrice=SUM((QtyOnSystem-Qty)*[dbo].[Item_AvgCost](ItemId, @DepartmentId)) from InventoryVoucherDetails where MainDocId=@Id and Qty<QtyOnSystem

	exec [dbo].[StockIssueVoucher_Insert] null,@BranchId ,@WarehouseId  ,@DepartmentId  ,@VoucherDate  ,@VendorOrCustomerId  ,@CurrencyId  ,@CurrencyEquivalent ,0  ,0  ,0  ,0  ,0  ,0  ,0  ,@Paid  ,
	@ValidityPeriod  ,@DeliveryPeriod  ,@CostPriceId  ,@CurrentQuantity  ,@DestinationWarehouseId  ,@SystemPageId  ,@Id  ,@TotalCostPrice  ,0  ,@IsDelivered  ,1  ,
	@IsLinked  ,@IsCompleted  ,@IsPosted  ,@UserId  ,@IsActive  ,@IsDeleted  ,1  ,@Notes  ,@Image  ,@UpdatedId,@StockIssueDetailsXml,1
end

if exists (select Id from InventoryVoucherDetails where MainDocId=@Id and Qty>QtyOnSystem )
begin
		declare @StockReceiptDetailsXml nvarchar(max)= (SELECT [MainDocId]
			,[ItemId]
           ,[Qty]-QtyOnSystem [Qty]
           ,[ItemPriceId]
           ,[Price]
           ,[ItemUnitId]
           ,[UnitEquivalent]
           ,[CurrencyId]
           ,[CurrencyEquivalent]
           ,[DiscountValue]
           ,[DiscountPerc]
           ,[WareHouseId]
           ,[WarrantyPeriod]
           ,[WarrantyStart]
           ,[ExpireDate]
           ,[PatchId]
           ,@SystemPageId [SystemPageId]
           ,@Id [SelectedId]
           ,[RemainQty]
           ,[dbo].[Item_AvgCost](ItemId, @DepartmentId) [CostPrice]
           ,[ItemDirectExpenses]
           ,[IsDeleted]
           ,[UpdatedId] from InventoryVoucherDetails where MainDocId=@Id and Qty>QtyOnSystem for xml raw ('Details'), root ('DocumentElement'), ELEMENTS)

	select @TotalCostPrice=SUM((Qty-QtyOnSystem)*[dbo].[Item_AvgCost](ItemId, @DepartmentId)) from InventoryVoucherDetails where MainDocId=@Id and Qty>QtyOnSystem

	exec [dbo].[StockReceiptVoucher_Insert] null, @BranchId, @WarehouseId, @DepartmentId, @VoucherDate, @VendorOrCustomerId, @CurrencyId, @CurrencyEquivalent,  0, 0, 0, 0  ,0  ,0  ,0  , @Paid, @ValidityPeriod, @DeliveryPeriod, @CostPriceId, @CurrentQuantity, @DestinationWarehouseId, @SystemPageId, @Id, @TotalCostPrice, 0, @IsDelivered, @IsAccepted,
@IsLinked  ,@IsCompleted  ,0  ,@UserId  ,@IsActive  ,@IsDeleted  ,1  ,@Notes  ,@Image  ,@UpdatedId,@StockReceiptDetailsXml,0,null
end
lbexit:
        if @trancount = 0
            commit;
    end try
    begin catch
        declare @error int, @message varchar(4000), @xstate int;
        select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        if @xstate = -1
            rollback;
        if @xstate = 1 and @trancount = 0
            rollback
        if @xstate = 1 and @trancount > 0
            rollback transaction InventoryVoucher_Adjustment;

        raiserror ('InventoryVoucher_Adjustment: %d: %s', 16, 1, @error, @message ) ;
    end catch
end

