CREATE PROC [dbo].[IssueAnalysis_Insert]
	-- Add the parameters for the stored procedure here
	@Id INT,
	@CashIssueVoucherId INT,
	@Value MONEY,
    @Reason NVARCHAR(MAX),
    @AccountId INT,
    @Notes NVARCHAR(MAX),
    @IsDeleted BIT,
    @Total MONEY,
    @Taxes MONEY,
    @TaxesPrecentage FLOAT,
    @NetTotal MONEY,
    @VendorId INT,
    @VendorArName NVARCHAR(MAX),
    @TaxNumber NVARCHAR(MAX),
    @VATNumber NVARCHAR(MAX),
    @InvoiceNo NVARCHAR(MAX),
	@IssueAnalysisDetails NTEXT
AS
begin
set nocount on;
    declare @trancount int;
	declare @IssueAnalysisDetailsOut int
    set @trancount = @@trancount;
    begin try
        if @trancount = 0
            begin transaction
        else
            save transaction IssueAnalysis_Insert;


    -- Insert statements for procedure here
-- ------------ IssueAnalysisDetails ------------------------
EXEC sp_xml_preparedocument @IssueAnalysisDetailsOut OUT, @IssueAnalysisDetails

INSERT INTO [dbo].IssueAnalysisDetail
           (IssueAnalysisId
		   ,PropertyDetailId
		   ,Price
		   )
SELECT @Id
           ,PropertyDetailId
		   ,Price

FROM OPENXML (@IssueAnalysisDetailsOut, '/DocumentElement/IssueAnalysisDetails', 2)
	with(       
		[IssueAnalysisId] int,
		[PropertyDetailId] int,
		[Price] money
	)
EXEC sp_xml_removedocument @IssueAnalysisDetailsOut

---------------------------------------------------------------------------------------------------------------------------------
lbexit:
        if @trancount = 0
            commit;
    end try
    begin catch
        declare @error int, @message varchar(4000), @xstate int;
        select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        if @xstate = -1
            rollback;
        if @xstate = 1 and @trancount = 0
            rollback
        if @xstate = 1 and @trancount > 0
            rollback transaction IssueAnalysis_Insert;

        raiserror ('IssueAnalysis_Insert: %d: %s', 16, 1, @error, @message ) ;
    end catch
end

