CREATE PROC [dbo].[IssueAnalysis_Update]
	-- Add the parameters for the stored procedure here
	@Id INT,	-- Id of the IssueAnalysis (if it exists)
	@CashIssueVoucherId INT,
	@Value MONEY,
    @Reason NVARCHAR(MAX),
    @AccountId INT,
    @Notes NVARCHAR(MAX),
    @IsDeleted BIT,
    @Total MONEY,
    @Taxes MONEY,
    @TaxesPrecentage FLOAT,
    @NetTotal MONEY,
    @VendorId INT,
    @VendorArName NVARCHAR(MAX),
    @TaxNumber NVARCHAR(MAX),
    @VATNumber NVARCHAR(MAX),
    @InvoiceNo NVARCHAR(MAX),
	@IssueAnalysisDetail NTEXT
AS
BEGIN
SET NOCOUNT ON;
    declare @trancount int;
    set @trancount = @@trancount;
    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION IssueAnalysis_Update;

        -- Declare a scalar variable to hold the new Id for IssueAnalysis
        DECLARE @NewIssueAnalysisId INT;
        DECLARE @IssueAnalysisDetailOut INT;

		-- Prepare the XML data for IssueAnalysisDetail
		EXEC sp_xml_preparedocument @IssueAnalysisDetailOut OUTPUT, @IssueAnalysisDetail;


        -- Check if the IssueAnalysis exists
        IF EXISTS (SELECT 1 FROM [dbo].[IssueAnalysis] WHERE [Id] = @Id)
        BEGIN
            -- If it exists, update the IssueAnalysis
            UPDATE [dbo].[IssueAnalysis]
            SET 
                [CashIssueVoucherId] = @CashIssueVoucherId,
                [Value] = @Value,
                [Reason] = @Reason,
                [AccountId] = @AccountId,
                [IsDeleted] = @IsDeleted,
                [Notes] = @Notes,
                [Total] = @Total,
                [Taxes] = @Taxes,
                [TaxesPrecentage] = @TaxesPrecentage,
                [NetTotal] = @NetTotal,
                [VendorId] = @VendorId,
                [VendorArName] = @VendorArName,
                [TaxNumber] = @TaxNumber,
                [VATNumber] = @VATNumber,
                [InvoiceNo] = @InvoiceNo
            WHERE [Id] = @Id;

            -- Set @NewIssueAnalysisId to the existing Id
            SET @NewIssueAnalysisId = @Id;
        END
        ELSE
        BEGIN
            -- If it doesn't exist, insert a new IssueAnalysis and capture the generated Id
            INSERT INTO [dbo].[IssueAnalysis] 
                ([CashIssueVoucherId], [Value], [Reason], [AccountId], [IsDeleted], [Notes], 
                [Total], [Taxes], [TaxesPrecentage], [NetTotal], [VendorId], [VendorArName], 
                [TaxNumber], [VATNumber], [InvoiceNo])
            VALUES 
                (@CashIssueVoucherId, @Value, @Reason, @AccountId, @IsDeleted, @Notes, 
                @Total, @Taxes, @TaxesPrecentage, @NetTotal, @VendorId, @VendorArName, 
                @TaxNumber, @VATNumber, @InvoiceNo);

            -- Capture the new Id using SCOPE_IDENTITY
            SET @NewIssueAnalysisId = SCOPE_IDENTITY();
        END

        -- Handle the IssueAnalysisDetail records
        -- Prepare the XML data for IssueAnalysisDetail
        DECLARE @IssueAnalysisDetailTemp TABLE (
            PropertyDetailId INT,
            Price MONEY,
            IssueAnalysisId INT
        );

        -- Parse the XML and insert into the temp table
        INSERT INTO @IssueAnalysisDetailTemp (PropertyDetailId, Price, IssueAnalysisId)
        SELECT
            PropertyDetailId,
            Price,
            @NewIssueAnalysisId -- Use the Id of the inserted/updated IssueAnalysis
        FROM OPENXML(@IssueAnalysisDetailOut, '/DocumentElement/IssueAnalysisDetails', 2)
        WITH (
            PropertyDetailId INT,
            Price MONEY,
            IssueAnalysisId INT
        );

        -- Delete existing IssueAnalysisDetail rows for the current IssueAnalysis (if any)
        DELETE FROM [dbo].[IssueAnalysisDetail]
        WHERE IssueAnalysisId = @NewIssueAnalysisId;

        -- Insert new IssueAnalysisDetail rows
        INSERT INTO [dbo].[IssueAnalysisDetail] (PropertyDetailId, Price, IssueAnalysisId)
        SELECT PropertyDetailId, Price, IssueAnalysisId
        FROM @IssueAnalysisDetailTemp;

        -- Remove the XML document handle
        EXEC sp_xml_removedocument @IssueAnalysisDetailOut;

        --------------------------------------------------------------------------------------------------------------------------------
        IF @trancount = 0
            COMMIT;
    END TRY
    begin catch
        declare @error int, @message varchar(4000), @xstate int;
        select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        if @xstate = -1
            rollback;
        if @xstate = 1 and @trancount = 0
            rollback
        if @xstate = 1 and @trancount > 0
            rollback transaction IssueAnalysis_Update;

        raiserror ('IssueAnalysis_Update: %d: %s', 16, 1, @error, @message ) ;
    end catch
end

