CREATE PROCEDURE [dbo].[ItemCostPrice_Insert]
	-- Add the parameters for the stored procedure here
	@ItemId [int] ,
	@Date [datetime] ,
	@InvoiceQty [float] ,
	@CostAfter [money] ,
	@SystemPageId [int] ,
	@SelectedId [int] ,
	@IsDelivered [bit] ,
	@IsAccepted [bit] ,
	@IsLinked [bit] ,
	@IsCompleted [bit] ,
	@IsPosted [bit] ,
	@UserId [int] ,
	@IsActive [bit] ,
	@IsDeleted [bit] ,
	@AutoCreated [bit] ,
	@Notes [nvarchar](max) ,
	@DepartmentId [int]
AS
BEGIN TRAN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
DECLARE @QtyAfter float=(select dbo.CalculateItemQuantityInWarehouse(null,@ItemId,null,null,@DepartmentId))

DECLARE @CostBefore money=isnull((select top 1 [CostAfter] from [ItemCostPrice] where [ItemId]=@ItemId and DepartmentId=@DepartmentId and [IsDeleted]=0 and [IsActive]=1 order by [Id] desc),0)
DECLARE @QtyBefore float= @QtyAfter - @InvoiceQty
DECLARE @AverageCost money
if((ISNULL( @QtyBefore,0)*1.0 + ISNULL(@InvoiceQty,0)*1.0)=0) --to handle zero qty divide for genoise
begin
 set @AverageCost =(ISNULL( @QtyBefore,0)* @CostBefore*1.0	+	ISNULL(@InvoiceQty,0)* ISNULL(@CostAfter,0)*1.0)
							/1
end
else 
begin
 set @AverageCost =(ISNULL( @QtyBefore,0)* @CostBefore*1.0	+	ISNULL(@InvoiceQty,0)* ISNULL(@CostAfter,0)*1.0)
							/(ISNULL( @QtyBefore,0)*1.0 + ISNULL(@InvoiceQty,0)*1.0)
end

INSERT INTO [dbo].[ItemCostPrice]
           ([ItemId]
           ,[Date]
           ,[QtyBefore]
           ,[QtyAfter]
           ,[CostBefore]
           ,[CostAfter]
           ,[SystemPageId]
           ,[SelectedId]
           ,[IsDelivered]
           ,[IsAccepted]
           ,[IsLinked]
           ,[IsCompleted]
           ,[IsPosted]
           ,[UserId]
           ,[IsActive]
           ,[IsDeleted]
           ,[AutoCreated]
           ,[Notes]
           ,DepartmentId)
     VALUES (@ItemId  ,
	@Date  ,
	ISNULL(@QtyBefore,0) ,
	ISNULL( @QtyAfter,0)  ,
	@CostBefore  ,
	@AverageCost  ,
	@SystemPageId  ,
	@SelectedId  ,
	@IsDelivered  ,
	@IsAccepted  ,
	@IsLinked  ,
	@IsCompleted  ,
	@IsPosted  ,
	@UserId  ,
	@IsActive  ,
	@IsDeleted  ,
	@AutoCreated  ,
	@Notes  ,
	@DepartmentId)

if @@error <>0
begin
rollback tran 
return 
end
else
begin
commit tran
end

CREATE proc [dbo].[JournalEntry_GetByIdDtl]
            @Id int
as
declare @SourcePageId int,@SourceId int,@SourceNo nvarchar(450)
select @SourcePageId = [SourcePageId],
       @SourceId = [SourceId]
from [dbo].[JournalEntry] where [Id] = @Id

if(@SourcePageId is not null and @SourceId is not null)
begin
EXEC [dbo].[SystemPage_GetSourceNo]
    @SourcePageId = @SourcePageId,
	@SourceId = @SourceId,
	@ColumnName = N'DocNo',
	@SourceNo = @SourceNo output
end

select j.[Id],j.[DocumentNumber],j.[CompanyId],c.[Code][CompanyCode],c.[ArName][CompanyNameAr],c.[EnName][CompanyNameEn],
j.[BranchId],b.[Code][BranchCode],b.[ArName][BranchNameAr],b.[EnName][BranchNameEn],
j.[Date],j.[DateHijri],j.[Notes],
j.[SourcePageId],j.[SourceId],p.[Code][SourceCode],p.[ArName][SourceAr],p.[EnName][SourceEn],
@SourceNo[SourceNo],j.[IsPosted],j.[UserId]
from [dbo].[JournalEntry] j left join [dbo].[Company] c on j.[CompanyId] = c.[Id]
left join [dbo].[Branch] b on j.[BranchId] = b.[Id]
left join [dbo].[SystemPage] p on j.[SourcePageId] = p.[Id]
where j.[Id] = @Id

