	@PaymentMethodId int,
	@OnlinePaymentNo nvarchar(MAX),
	@ChairPrice money,	
	@Chairs NTEXT

AS
begin
set nocount on;
    declare @trancount int;
    set @trancount = @@trancount;
    begin try
        if @trancount = 0
            begin transaction
        else
            save transaction PartyBooking_Insert;

    -- Insert statements for procedure here
declare @DocumentNumber int =  isnull((select top(1) convert (int,[DocumentNumber]) from PartyBooking where IsDeleted=0  order by [Id] desc),0)+1
DECLARE @ChairsOut int
-------------------------------------------------------------------------
	INSERT INTO [dbo].[PartyBooking]
  ([DocumentNumber],
    BookingDate,
	PartyId,
	ChairsNo,
	[UserId],
    [IsDeleted],
    [Notes],
    [Image],
	[Total],
	[Taxes],
	[TotalAfterTaxes],
	CustomerId,
	PaymentMethodId ,
	OnlinePaymentNo ,
	ChairPrice 
	)
     VALUES
    (cast (@DocumentNumber as nvarchar(max)),
	@BookingDate,
	@PartyId,
	@ChairsNo,
	@UserId,
    @IsDeleted,
    @Notes,
    @Image,
	@Total,
	@Taxes,
	@TotalAfterTaxes,
	@CustomerId,
	@PaymentMethodId ,
	@OnlinePaymentNo ,
	@ChairPrice 
	)

 set @Id  = (select MAX(Id) from [dbo].[PartyBooking])
 --//------------------------------------------------------------------------------------------------------------------------//---

 ---- reserve chairs of this party and partybooking 
 --//---------------------------- Chair Cursor--------------------------------------//--
 DECLARE @ChairsTable Table
([Id] int, IsReserved bit)
EXEC sp_xml_preparedocument @ChairsOut OUT, @Chairs
insert  into @ChairsTable
select Id,IsReserved
FROM OPENXML (@ChairsOut, '/DocumentElement/Chairs', 2)
with([Id] int, IsReserved bit)
EXEC sp_xml_removedocument @ChairsOut

declare @ChairId int,@IsReserved bit
declare ChairCur cursor for SELECT  Id ,IsReserved
FROM @ChairsTable  
open ChairCur
fetch next from ChairCur into @ChairId,@IsReserved
while @@FETCH_STATUS=0
begin 
if(@IsReserved =1)
begin
update Chair set IsReserved=@IsReserved,PartyBookingId=@Id where Id=@ChairId
end
else
begin
update Chair set IsReserved=null,PartyBookingId=null where Id=@ChairId
end		fetch next from ChairCur into @ChairId,@IsReserved
end
close ChairCur
deallocate ChairCur
 --//---------------------------- End Of Chair Cursor--------------------------------------//--

 -- // ------- Old Code -------- // --
 --update top (@ChairsNo)  Chair  set PartyBookingId = @Id , IsReserved=1 where IsActive=1 and IsDeleted=0 and PartyId=@PartyId and (IsReserved is null or IsReserved=0) 
 -- and Price=@ChairPrice--(@Total/@ChairsNo)

 ---------------------------------------------------------------------------------

---//-----------------------------------------------------------------------------------------------------------------//--
lbexit:
        if @trancount = 0
            commit;
    end try
    begin catch
        declare @error int, @message varchar(4000), @xstate int;
        select @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        if @xstate = -1
            rollback;
        if @xstate = 1 and @trancount = 0
            rollback
        if @xstate = 1 and @trancount > 0
            rollback transaction PartyBooking_Insert;

        raiserror ('PartyBooking_Insert: %d: %s', 16, 1, @error, @message ) ;
    end catch
end

