CREATE PROCEDURE [dbo].[PropertBillRegisteration_Insert]
    @Id int output,
    @BillRegDate datetime,
    @TransactionNumber INT,
    @ContractId INT,
    @RenterId INT,
    @PropertyDetailId INT,
    @ElectricityBillValue MONEY,
    @GasBillValue MONEY,
    @ViolationBillValue MONEY,
    @RentersAccount MONEY,
    @UserId INT,
    @DepartmentId INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @trancount int = @@TRANCOUNT;

    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION PropertyBillRegisteration_Insert;

        /* ===================== Insert PropertyBillRegisteration ===================== */

        INSERT INTO [dbo].[PropertyBillRegisteration]
        (
            [TransactionNumber], [BillRegDate], [ContractId], [RenterId], [PropertyDetailId],
            [GasBillValue], [ElectricityBillValue], [ViolationBillValue]
        )
        VALUES
        (
            @TransactionNumber, @BillRegDate, @ContractId, @RenterId, @PropertyDetailId,
            @GasBillValue, @ElectricityBillValue, @ViolationBillValue
        );

        DECLARE @PropertyBillRegisterationId int = CONVERT(INT, SCOPE_IDENTITY());
        SELECT @Id = @PropertyBillRegisterationId;

        UPDATE [dbo].[PropertyBillRegisteration]
        SET [TransactionNumber] = @Id
        WHERE Id = @Id;

        /* ===================== Generate JournalEntry DocumentNumber (SAFE) ===================== */

        DECLARE @JournalEntryDocNum NVARCHAR(MAX);

        EXEC dbo.GetNextDocumentNumberSafe
            @TableName = 'JournalEntry',
            @DepartmentId = @DepartmentId,
            @VoucherDate = @BillRegDate,
            @DocumentNumber = @JournalEntryDocNum OUTPUT;

        IF @JournalEntryDocNum IS NULL
        BEGIN
            RAISERROR('PropertBillRegisteration_Insert: Failed to generate JournalEntry document number.', 16, 1);
            RETURN;
        END

        /* ===================== Insert JournalEntry ===================== */

        DECLARE @SourcePageId int = (SELECT [Id] FROM [SystemPage] WHERE [TableName] = 'PropertyBillRegisteration');
        DECLARE @SourceId int = @Id;

        INSERT INTO [dbo].[JournalEntry]
        ([DocumentNumber], [Date], [SourceId], [SourcePageId], [IsActive], [IsPosted], [IsDeleted], [UserId], [DepartmentId])
        VALUES
        (@JournalEntryDocNum, @BillRegDate, @SourceId, @SourcePageId, 1, 0, 0, @UserId, @DepartmentId);

        DECLARE @JournalEntryId INT;

        SELECT TOP(1) @JournalEntryId = Id
        FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
        WHERE SourcePageId = @SourcePageId AND SourceId = @SourceId
        ORDER BY Id DESC;

        IF @JournalEntryId IS NULL
        BEGIN
            RAISERROR('PropertBillRegisteration_Insert: JournalEntryId not resolved.', 16, 1);
            RETURN;
        END

        /* ===================== Get Account IDs ===================== */

        DECLARE @ElectricityDueRevenueId int = (SELECT ElectricityDueRevenueId FROM [dbo].Department WHERE [Id] = @DepartmentId);
        DECLARE @GasDueRevenueId int = (SELECT GasDueRevenueId FROM [dbo].Department WHERE [Id] = @DepartmentId);
        DECLARE @ViolationsDueRevenueId int = (SELECT ViolationsDueRevenueId FROM [dbo].Department WHERE [Id] = @DepartmentId);
        DECLARE @RenterAndBuyerAccountId int = (SELECT RenterAndBuyerAccountId FROM [dbo].Department WHERE [Id] = @DepartmentId);

        /* ===================== Insert Journal Entry Details ===================== */

        INSERT INTO [dbo].[JournalEntryDetail]
        (
            [JournalEntryId], [Debit], [Credit], [AccountId], [SourcePageId], [SourceId],
            [IsActive], [IsPosted], [IsDeleted], [PartyType], [PartyId]
        )
        VALUES
        (@JournalEntryId, @RentersAccount, 0, @RenterAndBuyerAccountId, @SourcePageId, @SourceId, 1, 0, 0, 4, @RenterId),
        (@JournalEntryId, 0, @ElectricityBillValue, @ElectricityDueRevenueId, @SourcePageId, @SourceId, 1, 0, 0, NULL, NULL),
        (@JournalEntryId, 0, @GasBillValue, @GasDueRevenueId, @SourcePageId, @SourceId, 1, 0, 0, NULL, NULL),
        (@JournalEntryId, 0, @ViolationBillValue, @ViolationsDueRevenueId, @SourcePageId, @SourceId, 1, 0, 0, NULL, NULL);

lbexit:
        IF @trancount = 0
            COMMIT;
    END TRY
    BEGIN CATCH
        DECLARE @error int, @message varchar(4000), @xstate int;
        SELECT @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        IF @xstate = -1 ROLLBACK;
        IF @xstate = 1 AND @trancount = 0 ROLLBACK;
        IF @xstate = 1 AND @trancount > 0 ROLLBACK TRANSACTION PropertyBillRegisteration_Insert;

        RAISERROR ('PropertyBillRegisteration_Insert: %d: %s', 16, 1, @error, @message);
    END CATCH
END

CREATE PROCEDURE [dbo].[PropertyContract_Insert]
@Id int output,
@DocumentNum nvarchar(max),
@VoucherDate datetime,
@ContractTypeId int,
@PropertyId int,
@RentTypeId int,
@PropertyOwnerId int,
@PropertyRenterId int,
@RepId int,
@RentValue money,
@CommissionValue money,
@ServicesValue money,
@WaterValue money,
@NetTotal money,
@VATPercentage float,
@VATValue money,
@TotalAfterTaxes money,
@ContractStartDate datetime,
@ContractEndDate datetime,
@ContractPeriodNum int,
@ContractPeriodTypeId int,
@IsDeleted bit,
@UserId int,
@Notes nvarchar(MAX),
@Image nvarchar(MAX),
@PropertyUnitTypeId int,
@PropertyUnitId int,
@IncludeRentValueInVAT bit,
@IncludeWaterValueInVAT bit,
@ElectricityValue money,
@IncludeElectricityValueInVAT bit,
@GasValue money,
@GracePeriodDay int,
@GracePeriodMonth int,
@NumberOfBatches int,
@FirstBatchDate datetime,
@PeriodBetweenBatchesNum int,
@PeriodBetweenBatchesTypeId int,
@IsDivideWaterIntoBatches bit,
@IsDivideElectricityIntoBatches bit,
@UnifiedContractNumber nvarchar(MAX),
@IsAddedValue bit,
@ContractSpecialTerms nvarchar(MAX),
@JournalEntryId int,
@DepartmentId int,
@InsuranceValue money,
@IncludeInsuranceValueInVAT bit,
@IncludeGasValueInVAT bit,
@IncludeCommissionValueInVAT bit,
@IncludeServicesValueInVAT bit,
@GovernmentalOrPrivateContract int,
@IsRenewed bit,
@Batches NTEXT,
@Reps NTEXT,
@Images NTEXT,
@MergedUnits NTEXT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @trancount int = @@TRANCOUNT;

    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION PropertyContract_Insert;

        /* ===================== DocumentsCoding (SAFE) ===================== */

        DECLARE
            @NoOfDigit INT,
            @CodingTypeId INT,
            @IsZerosFills BIT,
            @YearFormat INT,
            @DocumentCodingCode NVARCHAR(50),
            @DocumentNumber NVARCHAR(MAX),
            @IsExistInDocumentsCoding BIT = 0;

        DECLARE @MonthToken NVARCHAR(2) = RIGHT('0' + CONVERT(NVARCHAR(2), MONTH(@VoucherDate)), 2);
        DECLARE @YearString NVARCHAR(4) = CONVERT(NVARCHAR(4), YEAR(@VoucherDate));

        DECLARE @DepartmentCode NVARCHAR(10) =
        (
            SELECT CONVERT(NVARCHAR(10), Code)
            FROM Department
            WHERE IsActive=1 AND IsDeleted=0 AND Id=@DepartmentId
        );

        IF (TRY_CONVERT(INT,@DepartmentCode) < 10)
            SET @DepartmentCode = '0' + @DepartmentCode;

        -- If Renewed contract, keep same DocumentNumber
        IF (@IsRenewed = 1)
        BEGIN
            SET @DocumentNumber = @DocumentNum;
        END
        ELSE
        BEGIN
            SET @DocumentCodingCode =
            (
                SELECT TOP(1) Code
                FROM DocumentsCoding
                WHERE IsActive=1 AND IsDeleted=0 AND DepartmentId=@DepartmentId
            );

            IF (@DocumentCodingCode IS NULL)
            BEGIN
                SET @DocumentCodingCode =
                (
                    SELECT TOP(1) Code
                    FROM DocumentsCoding
                    WHERE IsActive=1 AND IsDeleted=0 AND AllDepartments=1
                );

                IF (@DocumentCodingCode IS NULL)
                BEGIN
                    SET @IsExistInDocumentsCoding = 0;
                END
                ELSE
                BEGIN
                    SELECT TOP(1)
                        @NoOfDigit = DigitsNo,
                        @CodingTypeId = CodingTypeId,
                        @IsZerosFills = IsZerosFills,
                        @YearFormat = YearFormat
                    FROM DocumentsCoding
                    WHERE IsActive=1 AND IsDeleted=0 AND AllDepartments=1;

                    SET @IsExistInDocumentsCoding = 1;
                END
            END
            ELSE
            BEGIN
                SELECT TOP(1)
                    @NoOfDigit = DigitsNo,
                    @CodingTypeId = CodingTypeId,
                    @IsZerosFills = IsZerosFills,
                    @YearFormat = YearFormat
                FROM DocumentsCoding
                WHERE IsActive=1 AND IsDeleted=0 AND DepartmentId=@DepartmentId;

                SET @IsExistInDocumentsCoding = 1;
            END

            IF ISNULL(@NoOfDigit,0) = 0 SET @NoOfDigit = 4;

            DECLARE @YearToken NVARCHAR(4);
            IF ISNULL(@YearFormat,4) = 2
                SET @YearToken = RIGHT(@YearString,2);
            ELSE
                SET @YearToken = @YearString;

            -- Prefix حسب نوع التكويد (سنوي/شهري)
            DECLARE @PrefixMonth NVARCHAR(100) = @DepartmentCode + N'-' + @YearToken + N'-' + @MonthToken + N'-';
            DECLARE @PrefixYear  NVARCHAR(100) = @DepartmentCode + N'-' + @YearToken + N'-';

            DECLARE @Prefix NVARCHAR(100) =
                CASE WHEN ISNULL(@CodingTypeId,1) = 3 THEN @PrefixYear ELSE @PrefixMonth END;

            -- AppLock لتفادي التزامن
            DECLARE @LockName NVARCHAR(200) = N'PC_DOCNUM:' + @Prefix;

            DECLARE @lockResult INT;
            EXEC @lockResult = sys.sp_getapplock
                @Resource = @LockName,
                @LockMode = 'Exclusive',
                @LockOwner = 'Transaction',
                @LockTimeout = 15000;

            IF @lockResult < 0
                RAISERROR(N'Cannot acquire document number lock (PropertyContract).', 16, 1);

            DECLARE @NextSerial INT;

            ;WITH L AS
            (
                SELECT TRY_CONVERT(INT, PARSENAME(REPLACE(DocumentNumber,'-','.'), 1)) AS Serial
                FROM dbo.PropertyContract WITH (UPDLOCK, HOLDLOCK)
                WHERE DepartmentId = @DepartmentId
                  AND IsDeleted = 0
                  AND DocumentNumber LIKE @Prefix + N'%'
            )
            SELECT @NextSerial = ISNULL(MAX(Serial),0) + 1
            FROM L;

            DECLARE @SerialStr NVARCHAR(20) =
                CASE WHEN ISNULL(@IsZerosFills,1) = 1
                     THEN RIGHT(REPLICATE('0', @NoOfDigit) + CONVERT(NVARCHAR(20), @NextSerial), @NoOfDigit)
                     ELSE CONVERT(NVARCHAR(20), @NextSerial)
                END;

            IF @IsExistInDocumentsCoding = 1
                SET @DocumentNumber = @PrefixMonth + @SerialStr;  -- نفس الشكل القياسي Dept-Year-Month-Serial
            ELSE
                SET @DocumentNumber = @SerialStr;                 -- Old coding fallback
        END

        /* ===================== Insert Contract + SAFE @Id ===================== */

        DECLARE @BatchesOut int, @RepsOut int, @MergedUnitsOut int, @ImagesOut int;

        INSERT INTO [dbo].[PropertyContract]
        (
            DocumentNumber,
            VoucherDate,
            ContractTypeId,
            PropertyId,
            RentTypeId,
            PropertyOwnerId,
            PropertyRenterId,
            RepId,
            RentValue,
            CommissionValue,
            ServicesValue,
            WaterValue,
            NetTotal,
            VATPercentage,
            VATValue,
            TotalAfterTaxes,
            ContractStartDate,
            ContractEndDate,
            ContractPeriodNum,
            ContractPeriodTypeId,
            IsDeleted,
            UserId,
            Notes,
            Image,
            PropertyUnitTypeId,
            PropertyUnitId,
            IncludeRentValueInVAT,
            IncludeWaterValueInVAT,
            ElectricityValue,
            IncludeElectricityValueInVAT,
            GasValue,
            GracePeriodDay,
            GracePeriodMonth,
            NumberOfBatches,
            FirstBatchDate,
            PeriodBetweenBatchesNum,
            PeriodBetweenBatchesTypeId,
            IsDivideWaterIntoBatches,
            IsDivideElectricityIntoBatches,
            UnifiedContractNumber,
            IsAddedValue,
            ContractSpecialTerms,
            JournalEntryId,
            DepartmentId,
            InsuranceValue,
            IncludeInsuranceValueInVAT,
            IncludeGasValueInVAT,
            IncludeCommissionValueInVAT,
            IncludeServicesValueInVAT,
            GovernmentalOrPrivateContract,
            IsRenewed
        )
        VALUES
        (
            CAST(@DocumentNumber as nvarchar(max)),
            @VoucherDate,
            @ContractTypeId,
            @PropertyId,
            @RentTypeId,
            @PropertyOwnerId,
            @PropertyRenterId,
            @RepId,
            @RentValue,
            @CommissionValue,
            @ServicesValue,
            @WaterValue,
            @NetTotal,
            @VATPercentage,
            @VATValue,
            @TotalAfterTaxes,
            @ContractStartDate,
            @ContractEndDate,
            @ContractPeriodNum,
            @ContractPeriodTypeId,
            @IsDeleted,
            @UserId,
            @Notes,
            @Image,
            @PropertyUnitTypeId,
            @PropertyUnitId,
            @IncludeRentValueInVAT,
            @IncludeWaterValueInVAT,
            @ElectricityValue,
            @IncludeElectricityValueInVAT,
            @GasValue,
            @GracePeriodDay,
            @GracePeriodMonth,
            @NumberOfBatches,
            @FirstBatchDate,
            @PeriodBetweenBatchesNum,
            @PeriodBetweenBatchesTypeId,
            @IsDivideWaterIntoBatches,
            @IsDivideElectricityIntoBatches,
            @UnifiedContractNumber,
            @IsAddedValue,
            @ContractSpecialTerms,
            @JournalEntryId,
            @DepartmentId,
            @InsuranceValue,
            @IncludeInsuranceValueInVAT,
            @IncludeGasValueInVAT,
            @IncludeCommissionValueInVAT,
            @IncludeServicesValueInVAT,
            @GovernmentalOrPrivateContract,
            0
        );

        SET @Id = CONVERT(INT, SCOPE_IDENTITY());

        -- لو العملية تجديد، علِّم كل العقود السابقة بنفس رقم العقد أنها مجددة
        IF (@IsRenewed = 1)
        BEGIN
            UPDATE pc
            SET pc.IsRenewed = 1
            FROM dbo.PropertyContract AS pc WITH (UPDLOCK, ROWLOCK)
            WHERE pc.DocumentNumber = CAST(@DocumentNum AS nvarchar(max))
              AND pc.Id <> @Id
              AND pc.IsDeleted = 0;
        END

        /* ===================== Batches ===================== */
        EXEC sp_xml_preparedocument @BatchesOut OUT, @Batches;

        INSERT INTO [dbo].[PropertyContractBatch]
        (
            MainDocId,
            BatchNo,
            BatchDate,
            BatchRentValue,
            BatchRentValueTaxes,
            BatchWaterValue,
            BatchWaterValueTaxes,
            BatchElectricityValue,
            BatchElectricityValueTaxes,
            BatchCommissionValue,
            BatchTotal,
            JournalEntryId,
            IsDeleted,
            UserId,
            Notes,
            Image,
            IsDelivered,
            IsRegisteredAsDue,
            BatchCommissionValueTaxes,
            BatchGasValue,
            BatchGasValueTaxes,
            BatchServicesValue,
            BatchServicesValueTaxes,
            BatchInsuranceValue,
            BatchInsuranceValueTaxes,
            IsRegisteredAsRevenue
        )
        SELECT
            @Id,
            BatchNo,
            BatchDate,
            BatchRentValue,
            BatchRentValueTaxes,
            BatchWaterValue,
            BatchWaterValueTaxes,
            BatchElectricityValue,
            BatchElectricityValueTaxes,
            BatchCommissionValue,
            BatchTotal,
            JournalEntryId,
            IsDeleted,
            UserId,
            Notes,
            Image,
            CASE WHEN @IsRenewed = 1 THEN 0 ELSE IsDelivered END,
            IsRegisteredAsDue,
            BatchCommissionValueTaxes,
            BatchGasValue,
            BatchGasValueTaxes,
            BatchServicesValue,
            BatchServicesValueTaxes,
            BatchInsuranceValue,
            BatchInsuranceValueTaxes,
            IsRegisteredAsRevenue
        FROM OPENXML (@BatchesOut, '/DocumentElement/Batches', 2)
        WITH
        (
            MainDocId int,
            BatchNo int,
            BatchDate datetime,
            BatchRentValue money,
            BatchRentValueTaxes money,
            BatchWaterValue money,
            BatchWaterValueTaxes money,
            BatchElectricityValue money,
            BatchElectricityValueTaxes money,
            BatchCommissionValue money,
            BatchTotal money,
            JournalEntryId int,
            IsDeleted bit,
            UserId int,
            Notes nvarchar(MAX),
            Image nvarchar(MAX),
            IsDelivered bit,
            IsRegisteredAsDue bit,
            BatchCommissionValueTaxes money,
            BatchGasValue money,
            BatchGasValueTaxes money,
            BatchServicesValue money,
            BatchServicesValueTaxes money,
            BatchInsuranceValue money,
            BatchInsuranceValueTaxes money,
            IsRegisteredAsRevenue bit
        );

        EXEC sp_xml_removedocument @BatchesOut;

        /* ===================== Reps ===================== */
        EXEC sp_xml_preparedocument @RepsOut OUT, @Reps;

        INSERT INTO [dbo].[PropertyContractRep]
        (
            MainDocId,
            RepId,
            RepPercentage,
            IsDeleted,
            UserId,
            Notes,
            Image
        )
        SELECT
            @Id,
            RepId,
            RepPercentage,
            IsDeleted,
            UserId,
            Notes,
            Image
        FROM OPENXML (@RepsOut, '/DocumentElement/Reps', 2)
        WITH
        (
            MainDocId int,
            RepId int,
            RepPercentage float,
            IsDeleted bit,
            UserId int,
            Notes nvarchar(MAX),
            Image nvarchar(MAX)
        );

        EXEC sp_xml_removedocument @RepsOut;

        /* ===================== Images ===================== */
        EXEC sp_xml_preparedocument @ImagesOut OUT, @Images;

        INSERT INTO [dbo].[PropertyContractImage]
        (
            MainDocId,
            Image
        )
        SELECT
            @Id,
            Image
        FROM OPENXML (@ImagesOut, '/DocumentElement/Images', 2)
        WITH
        (
            MainDocId int,
            Image nvarchar(MAX)
        );

        EXEC sp_xml_removedocument @ImagesOut;

        /* ===================== MergedUnits ===================== */
        EXEC sp_xml_preparedocument @MergedUnitsOut OUT, @MergedUnits;

        INSERT INTO [dbo].[PropertyContractMergedUnit]
        (
            PropertyContractId,
            PropertyUnitId
        )
        SELECT
            @Id,
            PropertyUnitId
        FROM OPENXML (@MergedUnitsOut, '/DocumentElement/MergedUnits', 2)
        WITH
        (
            PropertyContractId int,
            PropertyUnitId int
        );

        EXEC sp_xml_removedocument @MergedUnitsOut;

        /* ===================== Update Units Status ===================== */
        UPDATE PropertyDetail
        SET StatusId = 1
        WHERE Id = @PropertyUnitId;

        UPDATE PropertyDetail
        SET StatusId = 1
        WHERE Id IN
        (
            SELECT PropertyUnitId
            FROM PropertyContractMergedUnit
            WHERE PropertyContractId = @Id
        );

lbexit:
        IF @trancount = 0
            COMMIT;
    END TRY
    BEGIN CATCH
        DECLARE @error int, @message varchar(4000), @xstate int;
        SELECT @error = ERROR_NUMBER(), @message = ERROR_MESSAGE(), @xstate = XACT_STATE();

        IF @xstate = -1 ROLLBACK;
        IF @xstate = 1 AND @trancount = 0 ROLLBACK;
        IF @xstate = 1 AND @trancount > 0 ROLLBACK TRANSACTION PropertyContract_Insert;

        RAISERROR ('PropertyContract_Insert: %d: %s', 16, 1, @error, @message);
    END CATCH

    SET NOCOUNT OFF;
END

-- ============================================================================
-- FIXED: PropertyContractJE_Insert
-- ============================================================================

CREATE PROCEDURE [dbo].[PropertyContractJE_Insert]
    @Id int
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @trancount int = @@TRANCOUNT;

    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION PropertyContractJE_Insert;

        DECLARE @VoucherDate datetime = (SELECT VoucherDate FROM PropertyContract WHERE Id=@Id);
        DECLARE @DepartmentId int = (SELECT DepartmentId FROM PropertyContract WHERE Id=@Id);
        DECLARE @UserId int = (SELECT UserId FROM PropertyContract WHERE Id=@Id);
        DECLARE @CurrencyId int = (SELECT TOP(1) Id FROM Currency WHERE IsDeleted=0 AND IsActive=1);
        DECLARE @CurrencyEquivalent float = (SELECT Equivalent FROM Currency WHERE Id=@CurrencyId);

        /* ===================== Generate JournalEntry DocumentNumber (SAFE) ===================== */

        DECLARE @JournalEntryDocNum NVARCHAR(MAX);

        EXEC dbo.GetNextDocumentNumberSafe
            @TableName = 'JournalEntry',
            @DepartmentId = @DepartmentId,
            @VoucherDate = @VoucherDate,
            @DocumentNumber = @JournalEntryDocNum OUTPUT;

        IF @JournalEntryDocNum IS NULL
        BEGIN
            RAISERROR('PropertyContractJE_Insert: Failed to generate JournalEntry document number.', 16, 1);
            RETURN;
        END

        DECLARE @SourcePageId int = (SELECT [Id] FROM [SystemPage] WHERE [TableName] = 'PropertyContract');

        DECLARE @PropertyRenterId INT;
        SELECT @PropertyRenterId = PropertyRenterId FROM dbo.PropertyContract WHERE Id = @Id;
        IF @PropertyRenterId IS NULL
        BEGIN
            RAISERROR('PropertyContractJE_Insert: Could not find a Renter for this Contract.', 16, 1);
            RETURN;
        END

        /* ===================== Get Account IDs and Values ===================== */

        DECLARE @RenterAndBuyerAccountId int = (SELECT RenterAndBuyerAccountId FROM Department WHERE [Id]=@DepartmentId);
        DECLARE @DueRentId int = (SELECT DueRentId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @FirstBatchValue money = (SELECT Top(1) BatchTotal FROM PropertyContractBatch WHERE [MainDocId]=@Id);
        DECLARE @ElectricityDueRevenueId int = (SELECT ElectricityDueRevenueId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @ElectricityValue money = (SELECT ElectricityValue FROM PropertyContract WHERE [Id]=@Id);
        DECLARE @WaterDueRevenueId int = (SELECT WaterDueRevenueId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @WaterValue money = (SELECT WaterValue FROM PropertyContract WHERE [Id]=@Id);
        DECLARE @ServicesDueRevenueId int = (SELECT ServicesDueRevenueId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @ServicesValue money = (SELECT ServicesValue FROM PropertyContract WHERE [Id]=@Id);
        DECLARE @CompanyDueCommissionId int = (SELECT CompanyDueCommissionId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @CommissionValue money = (SELECT CommissionValue FROM PropertyContract WHERE [Id]=@Id);
        DECLARE @GasDueRevenueId int = (SELECT GasDueRevenueId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @GasValue money = (SELECT GasValue FROM PropertyContract WHERE [Id]=@Id);
        DECLARE @PropertyRefundInsuranceId int = (SELECT PropertyRefundInsuranceId FROM [Department] WHERE [Id]=@DepartmentId);
        DECLARE @InsuranceValue money = (SELECT InsuranceValue FROM PropertyContract WHERE [Id]=@Id);

        DECLARE @SumValues money = ISNULL(@WaterValue,0) + ISNULL(@ServicesValue,0) + ISNULL(@CommissionValue,0) + ISNULL(@ElectricityValue,0) + ISNULL(@GasValue,0);
        DECLARE @NetFirstBatchValue money = ISNULL(@FirstBatchValue,0) - ISNULL(@SumValues,0) - ISNULL(@InsuranceValue,0);

        /* ===================== Insert JournalEntry ===================== */

        INSERT INTO [dbo].[JournalEntry]
        ([DocumentNumber], [BranchId], [Date], [SourcePageId], [SourceId], [IsActive], [IsPosted], [IsDeleted], [UserId], [DepartmentId], [CurrencyId], [Equivalent])
        VALUES
        (Cast(@JournalEntryDocNum as nvarchar(max)), null, @VoucherDate, @SourcePageId, @Id, 1, 0, 0, @UserId, @DepartmentId, @CurrencyId, @CurrencyEquivalent);

        DECLARE @JournalEntryId int;

        SELECT TOP(1) @JournalEntryId = Id
        FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
        WHERE SourcePageId = @SourcePageId AND SourceId = @Id
        ORDER BY Id DESC;

        IF @JournalEntryId IS NULL
        BEGIN
            RAISERROR('PropertyContractJE_Insert: JournalEntryId not resolved.', 16, 1);
            RETURN;
        END

        UPDATE dbo.PropertyContract SET JournalEntryId = @JournalEntryId WHERE Id = @Id;

        /* ===================== Build Journal Entry Details ===================== */

        DECLARE @JournalEntryDetail table(
            [JournalEntryId] [int] NULL, [Debit] [money] NULL, [Credit] [money] NULL, [CurrencyId] [int] NULL, [Equivalent] [float] NULL,
            [AccountId] [int] NULL, [SourcePageId] [int] NULL, [SourceId] [int] NULL, [IsPosted] [bit] NULL, [IsDeleted] [bit] NULL,
            [IsActive] [bit] NULL, CostCenterId int null, PartyType INT NULL, PartyId INT NULL
        );

        Insert into @JournalEntryDetail (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId, IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
        VALUES
            (@JournalEntryId, ISNULL(@NetFirstBatchValue,0), 0, @CurrencyId, @CurrencyEquivalent, @RenterAndBuyerAccountId, @SourcePageId, @Id, 0, 0, 1, null, 4, @PropertyRenterId),
            (@JournalEntryId, 0, ISNULL(@NetFirstBatchValue,0), @CurrencyId, @CurrencyEquivalent, @DueRentId, @SourcePageId, @Id, 0, 0, 1, null, null, null);

        Insert into @JournalEntryDetail (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId, IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
        VALUES
            (@JournalEntryId, ISNULL(@SumValues,0), 0, @CurrencyId, @CurrencyEquivalent, @RenterAndBuyerAccountId, @SourcePageId, @Id, 0, 0, 1, null, 4, @PropertyRenterId),
            (@JournalEntryId, 0, ISNULL(@ServicesValue,0), @CurrencyId, @CurrencyEquivalent, @ServicesDueRevenueId, @SourcePageId, @Id, 0, 0, 1, null, null, null),
            (@JournalEntryId, 0, ISNULL(@ElectricityValue,0), @CurrencyId, @CurrencyEquivalent, @ElectricityDueRevenueId, @SourcePageId, @Id, 0, 0, 1, null, null, null),
            (@JournalEntryId, 0, ISNULL(@WaterValue,0), @CurrencyId, @CurrencyEquivalent, @WaterDueRevenueId, @SourcePageId, @Id, 0, 0, 1, null, null, null),
            (@JournalEntryId, 0, ISNULL(@CommissionValue,0), @CurrencyId, @CurrencyEquivalent, @CompanyDueCommissionId, @SourcePageId, @Id, 0, 0, 1, null, null, null),
            (@JournalEntryId, 0, ISNULL(@GasValue,0), @CurrencyId, @CurrencyEquivalent, @GasDueRevenueId, @SourcePageId, @Id, 0, 0, 1, null, null, null);

        Insert into @JournalEntryDetail (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId, IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
        VALUES
            (@JournalEntryId, ISNULL(@InsuranceValue,0), 0, @CurrencyId, @CurrencyEquivalent, @PropertyRefundInsuranceId, @SourcePageId, @Id, 0, 0, 1, null, null, null),
            (@JournalEntryId, 0, ISNULL(@InsuranceValue,0), @CurrencyId, @CurrencyEquivalent, @RenterAndBuyerAccountId, @SourcePageId, @Id, 0, 0, 1, null, 4, @PropertyRenterId);

        Insert into [dbo].[JournalEntryDetail] (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId, IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
        SELECT JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId, IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId
        FROM @JournalEntryDetail WHERE Debit > 0 OR Credit > 0;

lbexit:
        IF @trancount = 0
            COMMIT;
    END TRY
    BEGIN CATCH
        DECLARE @error int, @message varchar(4000), @xstate int;
        SELECT @error = ERROR_NUMBER(), @message = ERROR_MESSAGE()+ ' at ' + cast(ERROR_LINE() as VARCHAR(50)), @xstate = XACT_STATE();
        IF @xstate = -1 ROLLBACK;
        IF @xstate = 1 AND @trancount = 0 ROLLBACK;
        IF @xstate = 1 AND @trancount > 0 ROLLBACK TRANSACTION PropertyContractJE_Insert;

        RAISERROR ('PropertyContractJE_Insert: %d: %s', 16, 1, @error, @message);
    END CATCH
END

CREATE PROCEDURE [dbo].[PropertyContractTerminate_Insert]
    @Id int output,
    @DepartmentId int,
    @VoucherDate datetime,
    @PropertyContractId int,
    @PropertyId int,
    @PropertyUnitTypeId int,
    @PropertyRenterId int,
    @TerminationDate datetime,
    @LastBatchDate datetime,
    @IsLastBatchCalculation bit,
    @IsDocumented bit,
    @IncreaseDayValue money,
    @IncreaseDaysNo int,
    @IncreaseDaysTotalValue money,
    @DecreaseDayValue money,
    @DecreaseDaysNo int,
    @DecreaseDaysTotalValue money,
    @IsDeleted bit,
    @UserId int,
    @Notes nvarchar(MAX),
    @Image nvarchar(MAX),
    @TotalUnpaidAmount  MONEY,
    @InsuranceAmount    MONEY,
    @RenterBalance      MONEY,
    @CalculationMethod  INT,
    @Details NTEXT,
    @Damages NTEXT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @trancount int = @@TRANCOUNT;

    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION PropertyContractTerminate_Insert;

        /* ===================== Generate PropertyContractTermination DocumentNumber (SAFE) ===================== */

        DECLARE @DocumentNumber NVARCHAR(MAX);

        EXEC dbo.GetNextDocumentNumberSafe
            @TableName = 'PropertyContractTermination',
            @DepartmentId = @DepartmentId,
            @VoucherDate = @VoucherDate,
            @DocumentNumber = @DocumentNumber OUTPUT;

        IF @DocumentNumber IS NULL
        BEGIN
            RAISERROR(N'PropertyContractTerminate_Insert: Failed to generate document number.', 16, 1);
            RETURN;
        END

        /* ===================== Insert PropertyContractTermination ===================== */

        DECLARE @SourcePageId int = (SELECT [Id] FROM [SystemPage] WHERE [TableName] = 'PropertyContractTermination');

        INSERT INTO [dbo].PropertyContractTermination
        (
            DocumentNumber, DepartmentId, VoucherDate, PropertyContractId, PropertyId, PropertyUnitTypeId, PropertyRenterId,
            TerminationDate, LastBatchDate, IsLastBatchCalculation, IsDocumented,
            IncreaseDayValue, IncreaseDaysNo, IncreaseDaysTotalValue, DecreaseDayValue, DecreaseDaysNo, DecreaseDaysTotalValue,
            IsDeleted, UserId, Notes, Image, TotalUnpaidAmount, InsuranceAmount, RenterBalance, CalculationMethod
        )
        VALUES
        (
            CAST(@DocumentNumber AS NVARCHAR(MAX)),
            @DepartmentId, @VoucherDate, @PropertyContractId, @PropertyId, @PropertyUnitTypeId, @PropertyRenterId,
            @TerminationDate, @LastBatchDate, @IsLastBatchCalculation, @IsDocumented,
            @IncreaseDayValue, @IncreaseDaysNo, @IncreaseDaysTotalValue, @DecreaseDayValue, @DecreaseDaysNo, @DecreaseDaysTotalValue,
            @IsDeleted, @UserId, @Notes, @Image, @TotalUnpaidAmount, @InsuranceAmount, @RenterBalance, @CalculationMethod
        );

        SET @Id = CONVERT(INT, SCOPE_IDENTITY());

        /* ===================== Insert Details (XML) ===================== */

        DECLARE @DetailsOut INT;
        EXEC sp_xml_preparedocument @DetailsOut OUTPUT, @Details;

        ;WITH XMLDetails AS
        (
            SELECT PropertyContractId, PropertyContractBatchId, IsDeleted, UserId, Notes, [Image], SequenceNo, Remain
            FROM OPENXML (@DetailsOut, '/DocumentElement/Details', 2)
            WITH
            (
                MainDocId INT, PropertyContractId INT, PropertyContractBatchId INT, IsDeleted BIT, UserId INT,
                Notes NVARCHAR(MAX), [Image] NVARCHAR(MAX), SequenceNo INT, Remain MONEY
            )
        )
        INSERT INTO dbo.PropertyContractTerminationDetail
        (MainDocId, PropertyContractId, PropertyContractBatchId, IsDeleted, UserId, Notes, [Image], SequenceNo, Remain)
        SELECT @Id, X.PropertyContractId, X.PropertyContractBatchId, X.IsDeleted, X.UserId, X.Notes, X.[Image], X.SequenceNo, X.Remain
        FROM XMLDetails X
        WHERE X.PropertyContractId = @PropertyContractId
          AND (X.PropertyContractBatchId IS NULL OR (X.PropertyContractBatchId > 0 AND EXISTS (SELECT 1 FROM dbo.PropertyContractBatch B WHERE B.Id = X.PropertyContractBatchId)));

        EXEC sp_xml_removedocument @DetailsOut;

        /* ===================== Insert Damages (XML) ===================== */

        DECLARE @DamagesOut INT;
        EXEC sp_xml_preparedocument @DamagesOut OUT, @Damages;

        INSERT INTO [dbo].PropertyContractTerminationDamage
        (
            PropertyContractTerminationId, PropertyComponentId, IsDeleted, UserId, Notes, Image, SequenceNo,
            PropertyComponentDetailId, Qty, Price
        )
        SELECT
            @Id, PropertyComponentId, IsDeleted, UserId, Notes, Image, SequenceNo,
            PropertyComponentDetailId, Qty, Price
        FROM OPENXML (@DamagesOut, '/DocumentElement/Damages', 2)
        WITH
        (
            PropertyContractTerminationId INT, PropertyComponentId INT, IsDeleted BIT, UserId INT, Notes NVARCHAR(MAX),
            Image NVARCHAR(MAX), SequenceNo INT, PropertyComponentDetailId INT, Qty FLOAT, Price MONEY
        );

        EXEC sp_xml_removedocument @DamagesOut;

        /* ===================== Generate JournalEntry DocumentNumber (SAFE) ===================== */

        DECLARE @CurrencyId INT = (SELECT TOP(1) Id FROM Currency WHERE IsDeleted=0 AND IsActive=1 ORDER BY Id);

        IF @CurrencyId IS NULL
            RAISERROR('PropertyContractTerminate_Insert: No active currency found.',16,1);

        DECLARE @CurrencyEquivalent FLOAT = (SELECT Equivalent FROM Currency WHERE Id=@CurrencyId);

        DECLARE @JournalEntryDocNum NVARCHAR(MAX);

        EXEC dbo.GetNextDocumentNumberSafe
            @TableName = 'JournalEntry',
            @DepartmentId = @DepartmentId,
            @VoucherDate = @VoucherDate,
            @DocumentNumber = @JournalEntryDocNum OUTPUT;

        IF @JournalEntryDocNum IS NULL
        BEGIN
            RAISERROR('PropertyContractTerminate_Insert: Failed to generate JournalEntry document number.', 16, 1);
            RETURN;
        END

        /* ===================== Create JournalEntry ===================== */

        INSERT INTO [dbo].[JournalEntry]
        (
            [DocumentNumber], [BranchId], [Date], [SourcePageId], [SourceId],
            [IsActive], [IsPosted], [IsDeleted], [UserId], [DepartmentId], [CurrencyId], [Equivalent]
        )
        VALUES
        (
            CAST(@JournalEntryDocNum AS NVARCHAR(MAX)), NULL, @VoucherDate, @SourcePageId, @Id,
            1, 0, 0, @UserId, @DepartmentId, @CurrencyId, @CurrencyEquivalent
        );

        DECLARE @JournalEntryId INT;

        SELECT TOP(1) @JournalEntryId = Id
        FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
        WHERE SourcePageId = @SourcePageId AND SourceId = @Id
        ORDER BY Id DESC;

        IF @JournalEntryId IS NULL
            RAISERROR('PropertyContractTerminate_Insert: JournalEntryId not resolved.',16,1);

        /* ===================== Build Journal Entry Details ===================== */

        DECLARE @RenterAccountId INT = (SELECT RenterAndBuyerAccountId FROM Department WHERE Id = @DepartmentId);
        DECLARE @RentDueAccountId INT = (SELECT RentRevenueId FROM Department WHERE Id = @DepartmentId);
        DECLARE @BranchServicesRevenue INT = (SELECT ServicesRevenueId FROM Department WHERE Id = @DepartmentId);

        IF @RenterAccountId IS NULL OR @RentDueAccountId IS NULL OR @BranchServicesRevenue IS NULL
            RAISERROR('PropertyContractTerminate_Insert: Department account mapping is incomplete.',16,1);

        DECLARE @DaysAmount MONEY =
            CASE
                WHEN ISNULL(@IncreaseDaysTotalValue,0) <> 0 THEN ISNULL(@IncreaseDaysTotalValue,0)
                WHEN ISNULL(@DecreaseDaysTotalValue,0) <> 0 THEN ISNULL(@DecreaseDaysTotalValue,0) * -1
                ELSE 0
            END;

        DECLARE @MainAmount MONEY = ISNULL(@TotalUnpaidAmount,0) + ISNULL(@InsuranceAmount,0) + ISNULL(@DaysAmount,0);

        DECLARE @DamagesAmount MONEY =
        (
            SELECT SUM(ISNULL(Qty,0) * ISNULL(Price,0))
            FROM dbo.PropertyContractTerminationDamage
            WHERE PropertyContractTerminationId = @Id AND ISNULL(IsDeleted,0) = 0
        );

        IF (@MainAmount > 0)
        BEGIN
            INSERT INTO dbo.JournalEntryDetail
            (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId,
             IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
            VALUES
            (@JournalEntryId, @MainAmount, 0, @CurrencyId, @CurrencyEquivalent, @RenterAccountId,
             @SourcePageId, @Id, 0, 0, 1, NULL, 4, @PropertyRenterId);

            INSERT INTO dbo.JournalEntryDetail
            (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId,
             IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
            VALUES
            (@JournalEntryId, 0, @MainAmount, @CurrencyId, @CurrencyEquivalent, @RentDueAccountId,
             @SourcePageId, @Id, 0, 0, 1, NULL, NULL, NULL);
        END;

        IF (@DamagesAmount > 0)
        BEGIN
            INSERT INTO dbo.JournalEntryDetail
            (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId,
             IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
            VALUES
            (@JournalEntryId, @DamagesAmount, 0, @CurrencyId, @CurrencyEquivalent, @RenterAccountId,
             @SourcePageId, @Id, 0, 0, 1, NULL, 4, @PropertyRenterId);

            INSERT INTO dbo.JournalEntryDetail
            (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId,
             IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
            VALUES
            (@JournalEntryId, 0, @DamagesAmount, @CurrencyId, @CurrencyEquivalent, @BranchServicesRevenue,
             @SourcePageId, @Id, 0, 0, 1, NULL, NULL, NULL);
        END;

lbexit:
        IF @trancount = 0
            COMMIT;
    END TRY
    BEGIN CATCH
        DECLARE @error int, @message varchar(4000), @xstate int;
        SELECT @error = ERROR_NUMBER(),
               @message = ERROR_MESSAGE()+ ' at ' + CAST(ERROR_LINE() AS VARCHAR(50)),
               @xstate = XACT_STATE();

        IF @xstate = -1 ROLLBACK;
        IF @xstate = 1 AND @trancount = 0 ROLLBACK;
        IF @xstate = 1 AND @trancount > 0 ROLLBACK TRANSACTION PropertyContractTerminate_Insert;

        RAISERROR ('PropertyContractTerminate_Insert: %d: %s', 16, 1, @error, @message);
    END CATCH
END

CREATE PROCEDURE [dbo].[PropertyContractTerminate_Update]
    @Id                 INT,
    @DocumentNumber     NVARCHAR(MAX),
    @DepartmentId       INT,
    @VoucherDate        DATETIME,
    @PropertyContractId INT,
    @PropertyId         INT,
    @PropertyUnitTypeId INT,
    @PropertyRenterId   INT,
    @TerminationDate    DATETIME,
    @LastBatchDate      DATETIME,
    @IsLastBatchCalculation BIT,
    @IsDocumented       BIT,
    @IncreaseDayValue   MONEY,
    @IncreaseDaysNo     INT,
    @IncreaseDaysTotalValue MONEY,
    @DecreaseDayValue   MONEY,
    @DecreaseDaysNo     INT,
    @DecreaseDaysTotalValue MONEY,
    @IsDeleted          BIT,
    @UserId             INT,
    @Notes              NVARCHAR(MAX),
    @Image              NVARCHAR(MAX),
    @TotalUnpaidAmount  MONEY,
    @InsuranceAmount    MONEY,
    @RenterBalance      MONEY,
    @CalculationMethod  INT,
    @Details            NTEXT,
    @Damages            NTEXT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @trancount INT = @@TRANCOUNT;

    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION PropertyContractTerminate_Update;

        DECLARE @SourcePageId INT =
        (
            SELECT [Id]
            FROM [SystemPage]
            WHERE [TableName] = 'PropertyContractTermination'
        );

        /*========================================================
            1) تحديث السجل الرئيسي
        ========================================================*/
        UPDATE [dbo].[PropertyContractTermination]
        SET [DocumentNumber]        = @DocumentNumber,
            [DepartmentId]          = @DepartmentId,
            [VoucherDate]           = @VoucherDate,
            [PropertyContractId]    = @PropertyContractId,
            [PropertyId]            = @PropertyId,
            [PropertyUnitTypeId]    = @PropertyUnitTypeId,
            [PropertyRenterId]      = @PropertyRenterId,
            [TerminationDate]       = @TerminationDate,
            [LastBatchDate]         = @LastBatchDate,
            [IsLastBatchCalculation]= @IsLastBatchCalculation,
            [IsDocumented]          = @IsDocumented,
            [IncreaseDayValue]      = @IncreaseDayValue,
            [IncreaseDaysNo]        = @IncreaseDaysNo,
            [IncreaseDaysTotalValue]= @IncreaseDaysTotalValue,
            [DecreaseDayValue]      = @DecreaseDayValue,
            [DecreaseDaysNo]        = @DecreaseDaysNo,
            [DecreaseDaysTotalValue]= @DecreaseDaysTotalValue,
            [IsDeleted]             = @IsDeleted,
            [UserId]                = @UserId,
            [Notes]                 = @Notes,
            [Image]                 = @Image,
            [TotalUnpaidAmount]     = @TotalUnpaidAmount,
            [InsuranceAmount]       = @InsuranceAmount,
            [RenterBalance]         = @RenterBalance,
            [CalculationMethod]     = @CalculationMethod
        WHERE [Id] = @Id;

        /*========================================================
            2) إعادة بناء التفاصيل من الـ XML
        ========================================================*/
        DECLARE @MainDocId INT = @Id;

        DELETE FROM dbo.PropertyContractTerminationDetail
        WHERE MainDocId = @MainDocId;

        DELETE FROM dbo.PropertyContractTerminationDamage
        WHERE PropertyContractTerminationId = @MainDocId;

        -- Details
        DECLARE @DetailsOut INT;
        EXEC sp_xml_preparedocument @DetailsOut OUTPUT, @Details;

        ;WITH XMLDetails AS
        (
            SELECT
                PropertyContractId,
                PropertyContractBatchId,
                IsDeleted,
                UserId,
                Notes,
                [Image],
                SequenceNo,
                Remain
            FROM OPENXML (@DetailsOut, '/DocumentElement/Details', 2)
            WITH
            (
                MainDocId               INT,
                PropertyContractId      INT,
                PropertyContractBatchId INT,
                IsDeleted               BIT,
                UserId                  INT,
                Notes                   NVARCHAR(MAX),
                [Image]                 NVARCHAR(MAX),
                SequenceNo              INT,
                Remain                  MONEY
            )
        )
        INSERT INTO dbo.PropertyContractTerminationDetail
        (
            MainDocId,
            PropertyContractId,
            PropertyContractBatchId,
            IsDeleted,
            UserId,
            Notes,
            [Image],
            SequenceNo,
            Remain
        )
        SELECT
            @Id,
            X.PropertyContractId,
            X.PropertyContractBatchId,
            X.IsDeleted,
            X.UserId,
            X.Notes,
            X.[Image],
            X.SequenceNo,
            X.Remain
        FROM XMLDetails X
        WHERE
            X.PropertyContractId = @PropertyContractId
            AND
            (
                X.PropertyContractBatchId IS NULL
                OR EXISTS
                (
                    SELECT 1
                    FROM dbo.PropertyContractBatch B
                    WHERE B.Id = X.PropertyContractBatchId
                )
            );

        EXEC sp_xml_removedocument @DetailsOut;

        -- Damages
        DECLARE @DamagesOut INT;
        EXEC sp_xml_preparedocument @DamagesOut OUTPUT, @Damages;

        INSERT INTO dbo.PropertyContractTerminationDamage
        (
            PropertyContractTerminationId,
            PropertyComponentId,
            IsDeleted,
            UserId,
            Notes,
            Image,
            SequenceNo,
            PropertyComponentDetailId,
            Qty,
            Price
        )
        SELECT
            @Id,
            PropertyComponentId,
            IsDeleted,
            UserId,
            Notes,
            Image,
            SequenceNo,
            PropertyComponentDetailId,
            Qty,
            Price
        FROM OPENXML (@DamagesOut, '/DocumentElement/Damages', 2)
        WITH
        (
            PropertyContractTerminationId INT,
            PropertyComponentId           INT,
            IsDeleted                     BIT,
            UserId                        INT,
            Notes                         NVARCHAR(MAX),
            Image                         NVARCHAR(MAX),
            SequenceNo                    INT,
            PropertyComponentDetailId     INT,
            Qty                           FLOAT,
            Price                         MONEY
        );

        EXEC sp_xml_removedocument @DamagesOut;

        /*========================================================
            3) تحديث/إنشاء قيد اليومية بأمان
        ========================================================*/
        DECLARE @CurrencyId INT =
        (
            SELECT TOP (1) Id
            FROM Currency
            WHERE IsDeleted = 0 AND IsActive = 1
            ORDER BY Id
        );

        IF @CurrencyId IS NULL
        BEGIN
            RAISERROR('PropertyContractTerminate_Update: No active currency found.',16,1);
            RETURN;
        END

        DECLARE @CurrencyEquivalent FLOAT =
        (
            SELECT Equivalent FROM Currency WHERE Id = @CurrencyId
        );

        DECLARE @JournalEntryDocNum NVARCHAR(100);

        -- لو الفنكشن بتعمل Lock داخلي تمام، لو لأ هنضيف Lock خارجي بسيط
        DECLARE @LockNameJE NVARCHAR(200) =
            N'JE_TERMINATION:DEPT=' + CONVERT(NVARCHAR(20), @DepartmentId)
            + N':Y=' + CONVERT(NVARCHAR(4), YEAR(@VoucherDate))
            + N':M=' + RIGHT('0' + CONVERT(NVARCHAR(2), MONTH(@VoucherDate)), 2);

        DECLARE @lockResult INT;
        EXEC @lockResult = sys.sp_getapplock
            @Resource = @LockNameJE,
            @LockMode = 'Exclusive',
            @LockOwner = 'Transaction',
            @LockTimeout = 15000;

        IF @lockResult < 0
            RAISERROR(N'Cannot acquire journal entry lock (Termination).', 16, 1);

        SELECT @JournalEntryDocNum = dbo.GetNextJournalEntryDocumentNumber(@DepartmentId, @VoucherDate);

        DECLARE @JournalEntryId INT;

        -- جلب الهيدر إن وجد (بـ Locks لتفادي race)
        SELECT TOP (1) @JournalEntryId = Id
        FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
        WHERE SourcePageId = @SourcePageId
          AND SourceId     = @Id
          AND ISNULL(IsDeleted,0) = ISNULL(@IsDeleted,0)
        ORDER BY Id DESC;

        IF @JournalEntryId IS NULL
        BEGIN
            INSERT INTO dbo.JournalEntry
            (
                [DocumentNumber],
                [Date],
                [Notes],
                [IsPosted],
                [IsDeleted],
                [IsActive],
                [UserId],
                [DepartmentId],
                [CurrencyId],
                [Equivalent],
                [SourcePageId],
                [SourceId]
            )
            VALUES
            (
                @JournalEntryDocNum,
                @VoucherDate,
                @Notes,
                0,
                @IsDeleted,
                1,
                @UserId,
                @DepartmentId,
                @CurrencyId,
                @CurrencyEquivalent,
                @SourcePageId,
                @Id
            );

            -- Resolve Id safely
            SELECT TOP (1) @JournalEntryId = Id
            FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
            WHERE SourcePageId = @SourcePageId
              AND SourceId     = @Id
            ORDER BY Id DESC;
        END
        ELSE
        BEGIN
            UPDATE dbo.JournalEntry
            SET DocumentNumber = @JournalEntryDocNum,
                [Date]        = @VoucherDate,
                [Notes]       = @Notes,
                [IsDeleted]   = @IsDeleted,
                [IsPosted]    = 0,
                [UserId]      = @UserId,
                [DepartmentId]= @DepartmentId,
                [CurrencyId]  = @CurrencyId,
                [Equivalent]  = @CurrencyEquivalent
            WHERE Id = @JournalEntryId;
        END

        IF @JournalEntryId IS NULL
        BEGIN
            RAISERROR('PropertyContractTerminate_Update: JournalEntryId not resolved.',16,1);
            RETURN;
        END

        -- امسح التفاصيل القديمة
        DELETE FROM dbo.JournalEntryDetail
        WHERE JournalEntryId = @JournalEntryId;

        /* حسابات الحسابات */
        DECLARE @RenterAccountId INT =
            (SELECT RenterAndBuyerAccountId FROM Department WHERE Id = @DepartmentId);

        DECLARE @RentDueAccountId INT =
            (SELECT RentRevenueId FROM Department WHERE Id = @DepartmentId);

        DECLARE @BranchServicesRevenue INT =
            (SELECT ServicesRevenueId FROM Department WHERE Id = @DepartmentId);

        IF @RenterAccountId IS NULL OR @RentDueAccountId IS NULL OR @BranchServicesRevenue IS NULL
        BEGIN
            RAISERROR('PropertyContractTerminate_Update: Department account mapping is incomplete.',16,1);
            RETURN;
        END

        -- مبلغ الأيام (زيادة أو نقص)
        DECLARE @DaysAmount MONEY =
            CASE
                WHEN ISNULL(@IncreaseDaysTotalValue,0) <> 0 THEN ISNULL(@IncreaseDaysTotalValue,0)
                WHEN ISNULL(@DecreaseDaysTotalValue,0) <> 0 THEN ISNULL(@DecreaseDaysTotalValue,0) * -1
                ELSE 0
            END;

        -- المبلغ الرئيسى: إجمالى المتبقى + التأمين + الأيام
        DECLARE @MainAmount MONEY =
            ISNULL(@TotalUnpaidAmount,0)
            + ISNULL(@InsuranceAmount,0)
            + ISNULL(@DaysAmount,0);

        -- إجمالى التلفيات
        DECLARE @DamagesAmount MONEY =
        (
            SELECT SUM(ISNULL(Qty,0) * ISNULL(Price,0))
            FROM dbo.PropertyContractTerminationDamage
            WHERE PropertyContractTerminationId = @Id
              AND ISNULL(IsDeleted,0) = 0
        );

        /* 3.1) من ح/ المستأجر → ح/ الإيجارات */
        IF (@MainAmount > 0)
        BEGIN
            INSERT INTO dbo.JournalEntryDetail
            (
                JournalEntryId, Debit, Credit, CurrencyId, Equivalent,
                AccountId, SourcePageId, SourceId,
                IsPosted, IsDeleted, IsActive,
                CostCenterId, PartyType, PartyId
            )
            VALUES
            (
                @JournalEntryId,
                @MainAmount, 0,
                @CurrencyId, @CurrencyEquivalent,
                @RenterAccountId,
                @SourcePageId, @Id,
                0, 0, 1,
                NULL, 4, @PropertyRenterId
            );

            INSERT INTO dbo.JournalEntryDetail
            (
                JournalEntryId, Debit, Credit, CurrencyId, Equivalent,
                AccountId, SourcePageId, SourceId,
                IsPosted, IsDeleted, IsActive,
                CostCenterId, PartyType, PartyId
            )
            VALUES
            (
                @JournalEntryId,
                0, @MainAmount,
                @CurrencyId, @CurrencyEquivalent,
                @RentDueAccountId,
                @SourcePageId, @Id,
                0, 0, 1,
                NULL, NULL, NULL
            );
        END;

        /* 3.2) التلفيات */
        IF (@DamagesAmount > 0)
        BEGIN
            INSERT INTO dbo.JournalEntryDetail
            (
                JournalEntryId, Debit, Credit, CurrencyId, Equivalent,
                AccountId, SourcePageId, SourceId,
                IsPosted, IsDeleted, IsActive,
                CostCenterId, PartyType, PartyId
            )
            VALUES
            (
                @JournalEntryId,
                @DamagesAmount, 0,
                @CurrencyId, @CurrencyEquivalent,
                @RenterAccountId,
                @SourcePageId, @Id,
                0, 0, 1,
                NULL, 4, @PropertyRenterId
            );

            INSERT INTO dbo.JournalEntryDetail
            (
                JournalEntryId, Debit, Credit, CurrencyId, Equivalent,
                AccountId, SourcePageId, SourceId,
                IsPosted, IsDeleted, IsActive,
                CostCenterId, PartyType, PartyId
            )
            VALUES
            (
                @JournalEntryId,
                0, @DamagesAmount,
                @CurrencyId, @CurrencyEquivalent,
                @BranchServicesRevenue,
                @SourcePageId, @Id,
                0, 0, 1,
                NULL, NULL, NULL
            );
        END;

lbexit:
        IF @trancount = 0
            COMMIT;
    END TRY
    BEGIN CATCH
        DECLARE @error   INT,
                @message VARCHAR(4000),
                @xstate  INT;

        SELECT  @error   = ERROR_NUMBER(),
                @message = ERROR_MESSAGE() + ' at ' + CAST(ERROR_LINE() AS VARCHAR(50)),
                @xstate  = XACT_STATE();

        IF @xstate = -1 ROLLBACK;
        IF @xstate = 1 AND @trancount = 0 ROLLBACK;
        IF @xstate = 1 AND @trancount > 0 ROLLBACK TRANSACTION PropertyContractTerminate_Update;

        RAISERROR ('PropertyContractTerminate_Update: %d: %s', 16, 1, @error, @message);
    END CATCH
END

CREATE PROCEDURE [dbo].[PropertyDueBatch_Insert]
    @Id int output,
    @DepartmentId int,
    @VoucherDate datetime,
    @FromDate date,
    @ToDate date,
    @IsDeleted bit,
    @UserId int,
    @Notes nvarchar(max),
    @Image nvarchar(max),
    @Details NTEXT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @trancount int = @@TRANCOUNT;

    BEGIN TRY
        IF @trancount = 0
            BEGIN TRANSACTION;
        ELSE
            SAVE TRANSACTION PropertyDueBatch_Insert;

        /* ===================== Generate PropertyDueBatch DocumentNumber (SAFE) ===================== */

        DECLARE @DocumentNumber NVARCHAR(MAX);

        -- FIX: Added OUTPUT keyword
        EXEC dbo.GetNextDocumentNumberSafe
            @TableName = 'PropertyDueBatch',
            @DepartmentId = @DepartmentId,
            @VoucherDate = @VoucherDate,
            @DocumentNumber = @DocumentNumber OUTPUT; -- << FIXED: Added OUTPUT

        IF @DocumentNumber IS NULL
        BEGIN
            RAISERROR('PropertyDueBatch_Insert: Failed to generate document number.', 16, 1);
            RETURN;
        END

        /* ===================== Insert PropertyDueBatch Header ===================== */

        DECLARE @SourcePageId INT = (SELECT [Id] FROM [SystemPage] WHERE [TableName] = 'PropertyDueBatch');

        INSERT INTO [dbo].PropertyDueBatch
        (
            DocumentNumber,
            DepartmentId,
            VoucherDate,
            FromDate,
            ToDate,
            IsDeleted,
            UserId,
            Notes,
            [Image]
        )
        VALUES
        (
            CAST(@DocumentNumber AS NVARCHAR(MAX)),
            @DepartmentId,
            @VoucherDate,
            @FromDate,
            @ToDate,
            @IsDeleted,
            @UserId,
            @Notes,
            @Image
        );

        SET @Id = CONVERT(INT, SCOPE_IDENTITY());

        /* ===================== Insert Details (XML) ===================== */

        DECLARE @DetailsOut INT;
        EXEC sp_xml_preparedocument @DetailsOut OUT, @Details;

        INSERT INTO [dbo].PropertyDueBatchDetail
        (
            MainDocId,
            PropertyContractId,
            PropertyContractBatchId,
            IsDeleted,
            UserId,
            Notes,
            [Image],
            IsSelected
        )
        SELECT
            @Id,
            PropertyContractId,
            PropertyContractBatchId,
            IsDeleted,
            UserId,
            Notes,
            [Image],
            IsSelected
        FROM OPENXML (@DetailsOut, '/DocumentElement/Details', 2)
        WITH
        (
            MainDocId INT,
            PropertyContractId INT,
            PropertyContractBatchId INT,
            IsDeleted BIT,
            UserId INT,
            Notes NVARCHAR(MAX),
            [Image] NVARCHAR(MAX),
            IsSelected BIT
        );

        EXEC sp_xml_removedocument @DetailsOut;

        /* ===================== Update PropertyContractBatch IsRegisteredAsDue ===================== */

        DECLARE @BatchId INT, @IsSelected BIT;

        DECLARE Cur CURSOR FOR
            SELECT PropertyContractBatchId, IsSelected
            FROM PropertyDueBatchDetail
            WHERE MainDocId = @Id;

        OPEN Cur;
        FETCH NEXT FROM Cur INTO @BatchId, @IsSelected;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            UPDATE PropertyContractBatch
            SET IsRegisteredAsDue = @IsSelected
            WHERE Id = @BatchId;

            FETCH NEXT FROM Cur INTO @BatchId, @IsSelected;
        END

        CLOSE Cur;
        DEALLOCATE Cur;

        /* ===================== Journal Entry ===================== */

        SELECT
            pc.Id AS ContractId,
            pc.PropertyRenterId,
            ISNULL(SUM(pcb.BatchTotal), 0) AS Sum_BatchTotal,
            ISNULL(MAX(pc.ElectricityValue), 0) AS Sum_ElectricityValue,
            ISNULL(MAX(pc.WaterValue), 0) AS Sum_WaterValue,
            ISNULL(MAX(pc.ServicesValue), 0) AS Sum_ServicesValue,
            ISNULL(MAX(pc.CommissionValue), 0) AS Sum_CommissionValue,
            ISNULL(MAX(pc.InsuranceValue), 0) AS Sum_InsuranceValue
        INTO #AggregatedTotals
        FROM
        (
            SELECT d.PropertyContractId, d.PropertyContractBatchId
            FROM dbo.PropertyDueBatchDetail d
            WHERE d.MainDocId = @Id AND ISNULL(d.IsSelected, 1) = 1
        ) AS SelectedDetails
        JOIN dbo.PropertyContractBatch pcb ON pcb.Id = SelectedDetails.PropertyContractBatchId
        JOIN dbo.PropertyContract pc ON pc.Id = pcb.MainDocId
        GROUP BY pc.Id, pc.PropertyRenterId;

        IF NOT EXISTS (
            SELECT 1 FROM #AggregatedTotals
            WHERE Sum_BatchTotal > 0 OR Sum_ElectricityValue > 0 OR Sum_WaterValue > 0
               OR Sum_ServicesValue > 0 OR Sum_CommissionValue > 0 OR Sum_InsuranceValue > 0
        )
        BEGIN
            DROP TABLE #AggregatedTotals;
            GOTO lbexit;
        END

        DECLARE @CustomerAccountId INT, @DueRentId INT, @ElectricityDueRevenueId INT,
                @WaterDueRevenueId INT, @ServicesDueRevenueId INT, @CompanyDueCommissionId INT,
                @PropertyRefundInsuranceId INT;

        SELECT
            @CustomerAccountId = RenterAndBuyerAccountId,
            @DueRentId = DueRentId,
            @ElectricityDueRevenueId = ElectricityDueRevenueId,
            @WaterDueRevenueId = WaterDueRevenueId,
            @ServicesDueRevenueId = ServicesDueRevenueId,
            @CompanyDueCommissionId = CompanyDueCommissionId,
            @PropertyRefundInsuranceId = PropertyRefundInsuranceId
        FROM dbo.Department
        WHERE Id = @DepartmentId;

        IF @CustomerAccountId IS NULL OR @DueRentId IS NULL OR @ElectricityDueRevenueId IS NULL
           OR @WaterDueRevenueId IS NULL OR @ServicesDueRevenueId IS NULL
           OR @CompanyDueCommissionId IS NULL OR @PropertyRefundInsuranceId IS NULL
        BEGIN
            RAISERROR('PropertyDueBatch_Insert: Department account mapping is incomplete.', 16, 1);
            RETURN;
        END

        DECLARE @CurrencyId INT, @CurrencyEquivalent FLOAT;
        SELECT TOP(1) @CurrencyId = Id, @CurrencyEquivalent = Equivalent
        FROM dbo.Currency
        WHERE IsDeleted = 0 AND IsActive = 1;

        IF @CurrencyId IS NULL
        BEGIN
            RAISERROR('PropertyDueBatch_Insert: No active currency found.', 16, 1);
            RETURN;
        END

        /* ===================== Generate JournalEntry DocumentNumber (SAFE) ===================== */

        DECLARE @JournalEntryDocNum NVARCHAR(MAX);

        -- FIX: Added OUTPUT keyword and fixed variable name
        EXEC dbo.GetNextDocumentNumberSafe
            @TableName = 'JournalEntry',
            @DepartmentId = @DepartmentId,
            @VoucherDate = @VoucherDate,
            @DocumentNumber = @JournalEntryDocNum OUTPUT; -- << FIXED

        IF @JournalEntryDocNum IS NULL
        BEGIN
            RAISERROR('PropertyDueBatch_Insert: Failed to generate JournalEntry document number.', 16, 1);
            RETURN;
        END

        INSERT INTO dbo.JournalEntry
        (
            DocumentNumber, BranchId, [Date], SourcePageId, SourceId, Notes,
            IsActive, IsPosted, IsDeleted, [Image], UserId, DepartmentId, CurrencyId, Equivalent
        )
        VALUES
        (
            @JournalEntryDocNum, NULL, @VoucherDate, @SourcePageId, @Id, @Notes,
            1, 0, 0, @Image, @UserId, @DepartmentId, @CurrencyId, @CurrencyEquivalent
        );

        DECLARE @JournalEntryId INT;
        SELECT TOP(1) @JournalEntryId = Id
        FROM dbo.JournalEntry WITH (UPDLOCK, HOLDLOCK)
        WHERE SourcePageId = @SourcePageId AND SourceId = @Id
        ORDER BY Id DESC;

        IF @JournalEntryId IS NULL
        BEGIN
            RAISERROR('PropertyDueBatch_Insert: JournalEntryId not resolved.', 16, 1);
            RETURN;
        END

        DECLARE @JournalEntryDetail TABLE
        (
            JournalEntryId INT, Debit MONEY, Credit MONEY, CurrencyId INT, Equivalent FLOAT,
            AccountId INT, SourcePageId INT, SourceId INT, IsPosted BIT, IsDeleted BIT,
            IsActive BIT, CostCenterId INT NULL, PartyType INT NULL, PartyId INT NULL
        );

        DECLARE @Loop_RenterId INT, @Loop_BatchTotal MONEY, @Loop_Electricity MONEY,
                @Loop_Water MONEY, @Loop_Services MONEY, @Loop_Commission MONEY, @Loop_Insurance MONEY;

        DECLARE totals_cursor CURSOR FOR
            SELECT PropertyRenterId, Sum_BatchTotal, Sum_ElectricityValue, Sum_WaterValue,
                   Sum_ServicesValue, Sum_CommissionValue, Sum_InsuranceValue
            FROM #AggregatedTotals;

        OPEN totals_cursor;
        FETCH NEXT FROM totals_cursor INTO @Loop_RenterId, @Loop_BatchTotal, @Loop_Electricity,
                                           @Loop_Water, @Loop_Services, @Loop_Commission, @Loop_Insurance;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            DECLARE @Loop_SumServices MONEY = ISNULL(@Loop_Services, 0) + ISNULL(@Loop_Electricity, 0)
                                            + ISNULL(@Loop_Water, 0) + ISNULL(@Loop_Commission, 0);

            IF @Loop_BatchTotal > 0
            BEGIN
                INSERT INTO @JournalEntryDetail
                (JournalEntryId, Debit, Credit, AccountId, PartyType, PartyId, CurrencyId, Equivalent,
                 SourcePageId, SourceId, IsPosted, IsDeleted, IsActive)
                VALUES
                (@JournalEntryId, @Loop_BatchTotal, 0, @CustomerAccountId, 4, @Loop_RenterId,
                 @CurrencyId, @CurrencyEquivalent, @SourcePageId, @Id, 0, 0, 1),
                (@JournalEntryId, 0, @Loop_BatchTotal, @DueRentId, NULL, NULL,
                 @CurrencyId, @CurrencyEquivalent, @SourcePageId, @Id, 0, 0, 1);
            END

            IF @Loop_SumServices > 0
            BEGIN
                INSERT INTO @JournalEntryDetail
                (JournalEntryId, Debit, Credit, AccountId, PartyType, PartyId, CurrencyId, Equivalent,
                 SourcePageId, SourceId, IsPosted, IsDeleted, IsActive)
                VALUES
                (@JournalEntryId, @Loop_SumServices, 0, @CustomerAccountId, 4, @Loop_RenterId,
                 @CurrencyId, @CurrencyEquivalent, @SourcePageId, @Id, 0, 0, 1);

                IF @Loop_Services > 0
                    INSERT INTO @JournalEntryDetail VALUES (@JournalEntryId, 0, @Loop_Services, @CurrencyId, @CurrencyEquivalent, @ServicesDueRevenueId, @SourcePageId, @Id, 0, 0, 1, NULL, NULL, NULL);
                IF @Loop_Electricity > 0
                    INSERT INTO @JournalEntryDetail VALUES (@JournalEntryId, 0, @Loop_Electricity, @CurrencyId, @CurrencyEquivalent, @ElectricityDueRevenueId, @SourcePageId, @Id, 0, 0, 1, NULL, NULL, NULL);
                IF @Loop_Water > 0
                    INSERT INTO @JournalEntryDetail VALUES (@JournalEntryId, 0, @Loop_Water, @CurrencyId, @CurrencyEquivalent, @WaterDueRevenueId, @SourcePageId, @Id, 0, 0, 1, NULL, NULL, NULL);
                IF @Loop_Commission > 0
                    INSERT INTO @JournalEntryDetail VALUES (@JournalEntryId, 0, @Loop_Commission, @CurrencyId, @CurrencyEquivalent, @CompanyDueCommissionId, @SourcePageId, @Id, 0, 0, 1, NULL, NULL, NULL);
            END

            IF @Loop_Insurance > 0
            BEGIN
                INSERT INTO @JournalEntryDetail
                (JournalEntryId, Debit, Credit, AccountId, PartyType, PartyId, CurrencyId, Equivalent,
                 SourcePageId, SourceId, IsPosted, IsDeleted, IsActive)
                VALUES
                (@JournalEntryId, @Loop_Insurance, 0, @PropertyRefundInsuranceId, NULL, NULL,
                 @CurrencyId, @CurrencyEquivalent, @SourcePageId, @Id, 0, 0, 1),
                (@JournalEntryId, 0, @Loop_Insurance, @CustomerAccountId, 4, @Loop_RenterId,
                 @CurrencyId, @CurrencyEquivalent, @SourcePageId, @Id, 0, 0, 1);
            END

            FETCH NEXT FROM totals_cursor INTO @Loop_RenterId, @Loop_BatchTotal, @Loop_Electricity,
                                               @Loop_Water, @Loop_Services, @Loop_Commission, @Loop_Insurance;
        END

        CLOSE totals_cursor;
        DEALLOCATE totals_cursor;
        DROP TABLE #AggregatedTotals;

        DECLARE @d MONEY, @c MONEY;
        SELECT @d = SUM(ISNULL(Debit, 0)), @c = SUM(ISNULL(Credit, 0)) FROM @JournalEntryDetail;

        IF ABS(ISNULL(@d, 0) - ISNULL(@c, 0)) > 0.01
        BEGIN
            RAISERROR('PropertyDueBatch_Insert: Journal not balanced (Debit <> Credit).', 16, 1);
            RETURN;
        END

        INSERT INTO dbo.JournalEntryDetail
        (JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId,
         IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId)
        SELECT JournalEntryId, Debit, Credit, CurrencyId, Equivalent, AccountId, SourcePageId, SourceId,
               IsPosted, IsDeleted, IsActive, CostCenterId, PartyType, PartyId
        FROM @JournalEntryDetail
        WHERE ISNULL(Debit, 0) <> 0 OR ISNULL(Credit, 0) <> 0;

lbexit:
        IF @trancount = 0
            COMMIT;
    END TRY
    BEGIN CATCH
        DECLARE @error INT, @message VARCHAR(4000), @xstate INT;
        SELECT @error = ERROR_NUMBER(),
               @message = ERROR_MESSAGE() + ' at ' + CAST(ERROR_LINE() AS VARCHAR(50)),
               @xstate = XACT_STATE();

        IF @xstate = -1 ROLLBACK;
        IF @xstate = 1 AND @trancount = 0 ROLLBACK;
        IF @xstate = 1 AND @trancount > 0 ROLLBACK TRANSACTION PropertyDueBatch_Insert;

        RAISERROR('PropertyDueBatch_Insert: %d: %s', 16, 1, @error, @message);
    END CATCH
END

CREATE   PROCEDURE [dbo].[PurchaseInvoice_Insert]
@Id int output,
@BranchId [int],
@WarehouseId [int],
@DepartmentId [int],
@VoucherDate [datetime],
@VendorOrCustomerId [int],
@CurrencyId [int],
@CurrencyEquivalent [float],
@Total [money],
@TotalItemsDiscount [money],
@SalesTaxes [money],
@TotalAfterTaxes [money],
@VoucherDiscountValue [money],
@VoucherDiscountPercentage [float],
@NetTotal [money],
@Paid [money],
@ValidityPeriod [float],
@DeliveryPeriod [float],
@CostCenterId [int],
@CurrentQuantity [float],
@DestinationWarehouseId [int],
@SystemPageId [int],
@SelectedId [int],
@TotalCostPrice [money],
@TotalItemDirectExpenses [money],
@CommercialRevenueTax [money],
@AddedPrecentageCost [float],
@IsDelivered [bit],
@IsAccepted [bit],
@IsLinked [bit],
@IsCompleted [bit],
@IsPosted [bit],
@UserId [int],
@IsActive [bit],
@IsDeleted [bit],
@AutoCreated [bit],
@Notes nvarchar,
@Image nvarchar,
@UpdatedId [int],
@Details NTEXT,
@PaymentMethods NTEXT,
@DirectExpenses NTEXT,
@SerialNumbers NTEXT,
@AlterPrices [bit],
@AlteredPrices NTEXT,
@DistributeItems bit,
@PatchDetails NTEXT,
@DueDate datetime,
@VendorInvoiceNumber nvarchar(max)
AS
BEGIN
SET NOCOUNT ON;

DECLARE @trancount int;
SET @trancount = @@trancount;

BEGIN TRY
	IF @trancount = 0
		BEGIN TRANSACTION;
	ELSE
		SAVE TRANSACTION PurchaseInvoice_Insert;

	Declare @NoOfDigit int,@CodingTypeId int,@IsZerosFills bit,@YearFormat int,@DocumentCodingCode nvarchar(50),
			@DocumentNumber nvarchar(max),@LastDocNo nvarchar(50),@length int,
			@Var nvarchar(50),@DocVar nvarchar(50),@DocNo nvarchar(50),@NewDocNo nvarchar(max);
	declare @IsExistInDocumentsCoding bit = 0;
	declare @MonthFormat nvarchar(20)= (select MONTH(@VoucherDate));
	declare @yearFormatString nvarchar(20)= (select convert(nvarchar(20),(Year(@VoucherDate))));
	declare @DepartmentCode nvarchar(max)= (select Code from Department where IsActive=1 and IsDeleted=0 and Id=@DepartmentId);

	if((select convert(int,@MonthFormat))<10) set @MonthFormat='0'+@MonthFormat;
	if((select convert(int,@DepartmentCode))<10) set @DepartmentCode='0'+(select convert(nvarchar(max),@DepartmentCode));

	set @DocumentCodingCode=(select top(1) Code from DocumentsCoding where IsActive=1 and IsDeleted=0 and DepartmentId=@DepartmentId);

	if(@DocumentCodingCode is null)
	begin
		set @DocumentCodingCode=(select top(1) Code from DocumentsCoding where IsActive=1 and IsDeleted=0 and AllDepartments=1);
		if(@DocumentCodingCode is null)
			set @IsExistInDocumentsCoding=0;
		else
		begin
			set @NoOfDigit=(select top(1) DigitsNo from DocumentsCoding where IsActive=1 and IsDeleted=0 and AllDepartments=1);
			set @CodingTypeId=(select top(1) CodingTypeId from DocumentsCoding where IsActive=1 and IsDeleted=0 and AllDepartments=1);
			set @IsZerosFills=(select top(1) IsZerosFills from DocumentsCoding where IsActive=1 and IsDeleted=0 and AllDepartments=1);
			set @YearFormat=(select top(1) YearFormat from DocumentsCoding where IsActive=1 and IsDeleted=0 and AllDepartments=1);
			set @IsExistInDocumentsCoding=1;
		end
	end
	else
	begin
		set @NoOfDigit=(select top(1) DigitsNo from DocumentsCoding where IsActive=1 and IsDeleted=0 and DepartmentId=@DepartmentId);
		set @CodingTypeId=(select top(1) CodingTypeId from DocumentsCoding where IsActive=1 and IsDeleted=0 and DepartmentId=@DepartmentId);
		set @IsZerosFills=(select top(1) IsZerosFills from DocumentsCoding where IsActive=1 and IsDeleted=0 and DepartmentId=@DepartmentId);
		set @YearFormat=(select top(1) YearFormat from DocumentsCoding where IsActive=1 and IsDeleted=0 and DepartmentId=@DepartmentId);
		set @IsExistInDocumentsCoding=1;
	end

	if(@IsExistInDocumentsCoding=1)
	begin
		if(@YearFormat=2) set @YearFormat=(select SUBSTRING(@yearFormatString,3,2));
		else set @YearFormat=(select convert(int,(select Year(@VoucherDate))));

		if(@CodingTypeId=1)
			set @LastDocNo=(select top(1)[DocumentNumber] from PurchaseInvoice where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 order by [Id] desc);
		else if(@CodingTypeId=2)
			set @LastDocNo=(select top(1)[DocumentNumber] from PurchaseInvoice where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 and MONTH(VoucherDate)=MONTH(@VoucherDate) and YEAR(VoucherDate)=YEAR(@VoucherDate) order by [Id] desc);
		else if(@CodingTypeId=3)
			set @LastDocNo=(select top(1)[DocumentNumber] from PurchaseInvoice where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 and YEAR(VoucherDate)=YEAR(@VoucherDate) order by [Id] desc);

		if (CHARINDEX('-',@LastDocNo) > 0)
		begin
			set @Var=(SELECT SUBSTRING(@LastDocNo,CHARINDEX('-', @LastDocNo, CHARINDEX('-', @LastDocNo) + 1)+1 ,LEN(@LastDocNo)));
			set @DocVar=(SELECT SUBSTRING(@Var,LEN(LEFT(@Var,CHARINDEX('-', @Var)+1)),LEN(@Var)-LEN(LEFT(@Var,CHARINDEX('-', @Var)))));
			set @DocNo=(select isnull(convert (int,@DocVar),0)+1);
		end
		else
			set @DocNo=(select isnull(convert (int,@LastDocNo),0)+1);

		set @length=@NoOfDigit-(select LEN(@DocNo));

		declare @i int=0;
		while (@i<@length)
		begin
			set @NewDocNo = (SELECT STUFF(@DocNo,1,0,'0'));
			set @DocNo = @NewDocNo;
			set @i=@i+1;
		end

		set @DocumentNumber=@DepartmentCode+'-'+convert(nvarchar(max),@YearFormat)+'-'+@MonthFormat+'-'+@NewDocNo;
	end
	else
	begin
		set @LastDocNo=(select top(1)[DocumentNumber] from PurchaseInvoice where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 order by [Id] desc);

		if (CHARINDEX('-',@LastDocNo) > 0)
		begin
			set @Var=(SELECT SUBSTRING(@LastDocNo,CHARINDEX('-', @LastDocNo, CHARINDEX('-', @LastDocNo) + 1)+1 ,LEN(@LastDocNo)));
			set @DocVar=(SELECT SUBSTRING(@Var,LEN(LEFT(@Var,CHARINDEX('-', @Var)+1)),LEN(@Var)-LEN(LEFT(@Var,CHARINDEX('-', @Var)))));
			set @DocumentNumber=(select convert(nvarchar(max),(select isnull(convert(int,@DocVar),0)+1)));
		end
		else
			set @DocumentNumber=(select isnull(convert(int,@LastDocNo),0)+1);
	end

	DECLARE @DetailsOut int,@SerialNumbersOut int,@PaymentMethodsOut int,@DirectExpensesOut int,@PatchDetailsOut int;
	DECLARE @SourcePageId int = (select [Id] from [SystemPage] where [TableName] = 'PurchaseInvoice');

	INSERT INTO [dbo].PurchaseInvoice
	(
		[DocumentNumber],[BranchId],[WarehouseId],[DepartmentId],[VoucherDate],[VendorOrCustomerId],[CurrencyId],[CurrencyEquivalent],
		[Total],[TotalItemsDiscount],[SalesTaxes],[TotalAfterTaxes],[VoucherDiscountValue],[VoucherDiscountPercentage],[NetTotal],[Paid],
		[ValidityPeriod],[DeliveryPeriod],[CostCenterId],[CurrentQuantity],[DestinationWarehouseId],[SystemPageId],[SelectedId],[TotalCostPrice],
		[TotalItemDirectExpenses],[AddedPrecentageCost],[IsDelivered],[IsAccepted],[IsLinked],[IsCompleted],[IsPosted],[UserId],[IsActive],[IsDeleted],
		[AutoCreated],[Notes],[Image],[UpdatedId],[WarehouseItemDistribution],CommercialRevenueTaxAmount,[DueDate],VendorInvoiceNumber
	)
	VALUES
	(
		cast(@DocumentNumber as nvarchar(max)),@BranchId,@WarehouseId,@DepartmentId,@VoucherDate,@VendorOrCustomerId,@CurrencyId,@CurrencyEquivalent,
		@Total,@TotalItemsDiscount,@SalesTaxes,@TotalAfterTaxes,@VoucherDiscountValue,@VoucherDiscountPercentage,@NetTotal,@Paid,
		@ValidityPeriod,@DeliveryPeriod,@CostCenterId,@CurrentQuantity,@DestinationWarehouseId,@SystemPageId,@SelectedId,@TotalCostPrice,
		@TotalItemDirectExpenses,@AddedPrecentageCost,@IsDelivered,@IsAccepted,@IsLinked,@IsCompleted,0,@UserId,@IsActive,@IsDeleted,
		@AutoCreated,@Notes,@Image,@UpdatedId,@DistributeItems,ISNULL(@CommercialRevenueTax,0),@DueDate,@VendorInvoiceNumber
	);

	set @Id =(select MAX([Id]) from PurchaseInvoice);

	EXEC sp_xml_preparedocument @PatchDetailsOut OUT, @PatchDetails;
	INSERT INTO [dbo].Patch([ItemId],[ExpireDate],[Code],[SystemPageId],[SelectedId])
	SELECT [ItemId],[ExpireDate],[PatchCode],57,@Id
	FROM OPENXML (@PatchDetailsOut, '/DocumentElement/PatchDetails',2)
	with([ItemId] [int],[ExpireDate] [datetime],[PatchCode] nvarchar(450));
	EXEC sp_xml_removedocument @PatchDetailsOut;

	EXEC sp_xml_preparedocument @DetailsOut OUT, @Details;
	INSERT INTO [dbo].PurchaseInvoiceDetails
	(
		[MainDocId],[ItemId],[Qty],[ItemPriceId],[Price],[ItemUnitId],[UnitEquivalent],[CurrencyId],[CurrencyEquivalent],
		[DiscountValue],[DiscountPerc],[WareHouseId],[WarrantyPeriod],[WarrantyStart],[ExpireDate],[PatchId],[SystemPageId],[SelectedId],
		[RemainQty],[CostPrice],[ItemDirectExpenses],[IsDeleted],[UpdatedId],[Notes],PatchCode,
		CarTypeId,CarModelId,CarColorId,ChassisNo,EngineNo,ManufacturingYear,PlateNo,VehicleNotes
	)
	SELECT
		@Id,[ItemId],[Qty],[ItemPriceId],[Price],[ItemUnitId],[UnitEquivalent],[CurrencyId],[CurrencyEquivalent],
		[DiscountValue],[DiscountPerc],[WareHouseId],[WarrantyPeriod],[WarrantyStart],[ExpireDate],[PatchId],[SystemPageId],[SelectedId],
		[RemainQty],[CostPrice],[ItemDirectExpenses],[IsDeleted],[UpdatedId],[Notes],PatchCode,
		NULLIF(CarTypeId,0),
		NULLIF(CarModelId,0),
		NULLIF(CarColorId,0),
		NULLIF(LTRIM(RTRIM(ChassisNo)),''),
		NULLIF(LTRIM(RTRIM(EngineNo)),''),
		NULLIF(ManufacturingYear,0),
		NULLIF(LTRIM(RTRIM(PlateNo)),''),
		NULLIF(LTRIM(RTRIM(VehicleNotes)),'')
	FROM OPENXML (@DetailsOut, '/DocumentElement/Details', 2)
	with(
		[MainDocId] [int],[ItemId] [int],[Qty] [float],[ItemPriceId] [int],[Price] [money],[ItemUnitId] [int],[UnitEquivalent] [float],
		[CurrencyId] [int],[CurrencyEquivalent] [float],[DiscountValue] [money],[DiscountPerc] [float],[WareHouseId] [int],[WarrantyPeriod] [float],
		[WarrantyStart] [datetime],[ExpireDate] [datetime],[PatchId] [int],[SystemPageId] [int],[SelectedId] [int],[RemainQty] [float],
		[CostPrice] [money],[ItemDirectExpenses] [money],[IsDeleted] [bit],[UpdatedId] [int],[Notes] nvarchar(MAX),PatchCode nvarchar(max),
		CarTypeId int,CarModelId int,CarColorId int,ChassisNo nvarchar(100),EngineNo nvarchar(100),ManufacturingYear int,PlateNo nvarchar(50),VehicleNotes nvarchar(500)
	);
	EXEC sp_xml_removedocument @DetailsOut;

	update PurchaseInvoiceDetails
	set PatchId=(select top(1) Id from Patch where Patch.ItemId=PurchaseInvoiceDetails.ItemId and convert(nvarchar,Patch.[ExpireDate],103)=convert(nvarchar,PurchaseInvoiceDetails.[ExpireDate],103))
	where MainDocId=@Id;

	IF OBJECT_ID('dbo.VehicleStock','U') IS NOT NULL
	BEGIN
		;WITH src AS
		(
			SELECT
				d.Id AS PurchaseInvoiceDetailId,
				d.ItemId,
				d.ChassisNo,
				d.EngineNo,
				d.CarTypeId,
				d.CarModelId,
				d.CarColorId,
				d.ManufacturingYear,
				d.PlateNo,
				d.VehicleNotes,
				d.CostPrice
			FROM dbo.PurchaseInvoiceDetails d
			WHERE d.MainDocId = @Id
			  AND d.IsDeleted = 0
			  AND d.ChassisNo IS NOT NULL
			  AND LTRIM(RTRIM(d.ChassisNo)) <> ''
		)
		MERGE dbo.VehicleStock AS tgt
		USING src
		   ON tgt.IsDeleted = 0
		  AND LOWER(LTRIM(RTRIM(tgt.ChassisNo))) = LOWER(LTRIM(RTRIM(src.ChassisNo)))
		WHEN MATCHED THEN
		  UPDATE SET
			  tgt.ItemId = src.ItemId,
			  tgt.EngineNo = src.EngineNo,
			  tgt.CarTypeId = src.CarTypeId,
			  tgt.CarModelId = src.CarModelId,
			  tgt.CarColorId = src.CarColorId,
			  tgt.ManufacturingYear = src.ManufacturingYear,
			  tgt.PlateNo = src.PlateNo,
			  tgt.VehicleNotes = src.VehicleNotes,
			  tgt.PurchaseInvoiceId = @Id,
			  tgt.PurchaseInvoiceDetailId = src.PurchaseInvoiceDetailId,
			  tgt.PurchaseDate = @VoucherDate,
			  tgt.PurchaseCost = src.CostPrice,
			  tgt.WarehouseId = @WarehouseId,
			  tgt.BranchId = @BranchId,
			  tgt.VehicleStatusId = 1,
			  tgt.SalesInvoiceId = NULL,
			  tgt.SalesInvoiceDetailId = NULL,
			  tgt.SalesDate = NULL,
			  tgt.SalePrice = NULL,
			  tgt.UpdatedDate = GETDATE()
		WHEN NOT MATCHED BY TARGET THEN
		  INSERT
		  (
			  ItemId,ChassisNo,EngineNo,CarTypeId,CarModelId,CarColorId,ManufacturingYear,PlateNo,VehicleNotes,
			  PurchaseInvoiceId,PurchaseInvoiceDetailId,PurchaseDate,PurchaseCost,WarehouseId,BranchId,
			  VehicleStatusId,IsDeleted,UserId,CreatedDate,UpdatedDate
		  )
		  VALUES
		  (
			  src.ItemId,src.ChassisNo,src.EngineNo,src.CarTypeId,src.CarModelId,src.CarColorId,src.ManufacturingYear,src.PlateNo,src.VehicleNotes,
			  @Id,src.PurchaseInvoiceDetailId,@VoucherDate,src.CostPrice,@WarehouseId,@BranchId,
			  1,0,@UserId,GETDATE(),GETDATE()
		  );
	END;

	EXEC sp_xml_preparedocument @DirectExpensesOut OUT, @DirectExpenses;
	INSERT INTO [dbo].[PurchaseInvoiceDirectExpenses]
	(
		[PurchaseInvoiceId],[DirectExpensesId],[Amount],[TaxesAmount],[TotalAmount],[PaymentMethod],[CashBoxId],[VendorId],[EmployeeId]
	)
	SELECT
		@Id,[DirectExpensesId],[Amount],[TaxesAmount],[TotalAmount],[PaymentMethod],[CashBoxId],[VendorId],[EmployeeId]
	FROM OPENXML (@DirectExpensesOut, '/DocumentElement/DirectExpenses', 2)
	with([MainDocId] [int],[DirectExpensesId] [int],[Amount] [money],[TaxesAmount] [money],[TotalAmount] [money],[PaymentMethod] [nvarchar](50),[CashBoxId] [int],[VendorId] [int],[EmployeeId] [int]);
	EXEC sp_xml_removedocument @DirectExpensesOut;

	EXEC sp_xml_preparedocument @PaymentMethodsOut OUT, @PaymentMethods;
	INSERT INTO [dbo].[PurchaseInvoicePaymentMethods]
	(
		[PurchaseInvoiceId],SystemPageId,[PaymentMethodId],[Amount],[CashBoxId],[BankId],[BankAccountId],[PaidAmount]
	)
	SELECT
		@Id AS [PurchaseInvoiceId],@SourcePageId,[PaymentMethodId],[Amount],[CashBoxId],[BankId],[BankAccountId],0
	FROM OPENXML (@PaymentMethodsOut, '/DocumentElement/PaymentMethods', 2)
	with([PurchaseInvoiceId] [int],SystemPageId [int],[PaymentMethodId][int],[Amount][money],[CashBoxId][int],[BankId][int],[BankAccountId][int]);
	EXEC sp_xml_removedocument @PaymentMethodsOut;

	DECLARE @JournalEntryDocNum nvarchar(max);

	if(@IsExistInDocumentsCoding=1)
	begin
		if(@YearFormat=2) set @YearFormat=(select SUBSTRING(@yearFormatString,3,2));
		else set @YearFormat=(select convert(int,(select Year(@VoucherDate))));

		if(@CodingTypeId=1)
			set @LastDocNo=(select top(1)[DocumentNumber] from JournalEntry where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 order by [Id] desc);
		else if(@CodingTypeId=2)
			set @LastDocNo=(select top(1)[DocumentNumber] from JournalEntry where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 and MONTH(Date)=MONTH(@VoucherDate) and YEAR(Date)=YEAR(@VoucherDate) order by [Id] desc);
		else if(@CodingTypeId=3)
			set @LastDocNo=(select top(1)[DocumentNumber] from JournalEntry where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 and YEAR(Date)=YEAR(@VoucherDate) order by [Id] desc);

		if (CHARINDEX('-',@LastDocNo) > 0)
		begin
			set @Var=(SELECT SUBSTRING(@LastDocNo,CHARINDEX('-', @LastDocNo, CHARINDEX('-', @LastDocNo) + 1)+1 ,LEN(@LastDocNo)));
			set @DocVar=(SELECT SUBSTRING(@Var,LEN(LEFT(@Var,CHARINDEX('-', @Var)+1)),LEN(@Var)-LEN(LEFT(@Var,CHARINDEX('-', @Var)))));
			set @DocNo=(select isnull(convert (int,@DocVar),0)+1);
		end
		else
			set @DocNo=(select isnull(convert (int,@LastDocNo),0)+1);

		set @length=@NoOfDigit-(select LEN(@DocNo));

		set @i=0;
		while (@i<@length)
		begin
			set @NewDocNo=(SELECT STUFF(@DocNo,1,0,'0'));
			set @DocNo=@NewDocNo;
			set @i=@i+1;
		end

		set @JournalEntryDocNum=@DepartmentCode+'-'+convert(nvarchar(max),@YearFormat)+'-'+@MonthFormat+'-'+@NewDocNo;
	end
	else
	begin
		set @LastDocNo=(select top(1)[DocumentNumber] from JournalEntry where [DepartmentId]=@DepartmentId and IsActive=1 and IsDeleted=0 order by [Id] desc);
		if (CHARINDEX('-',@LastDocNo) > 0)
		begin
			set @Var=(SELECT SUBSTRING(@LastDocNo,CHARINDEX('-', @LastDocNo, CHARINDEX('-', @LastDocNo) + 1)+1 ,LEN(@LastDocNo)));
			set @DocVar=(SELECT SUBSTRING(@Var,LEN(LEFT(@Var,CHARINDEX('-', @Var)+1)),LEN(@Var)-LEN(LEFT(@Var,CHARINDEX('-', @Var)))));
			set @JournalEntryDocNum=(select convert(nvarchar(max),(select isnull(convert (int,@DocVar),0)+1)));
		end
		else
			set @JournalEntryDocNum=(select isnull(convert(int,@LastDocNo),0)+1);
	end

	DECLARE @PurchaseAccountId int;
	declare @UseSeparatedAccountsForWarehouse bit=(select top(1) UseSeparatedAccountsForWarehouse from SystemSetting);
	if(@UseSeparatedAccountsForWarehouse=1) set @PurchaseAccountId=(select StockAccountId from Warehouse where [Id]=@WarehouseId);
	else set @PurchaseAccountId=(select InventoryAccountId from [Department] where [Id]=@DepartmentId);

	DECLARE @DebitValueAddedTaxesAccountId int=(select DebitValueAddedTaxesAccountId from [Department] where [Id]=@DepartmentId);
	DECLARE @AcquiredDeductionAccountId int=(select [AcquiredDeductionAccountId] from [Department] where [Id]=@DepartmentId);
	DECLARE @CommercialRevenueTaxAccountId money=(select CommercialRevenueTaxAccountId from Department where Id=@DepartmentId);
	DECLARE @VendorAccountId int=(select VendorsAccountId from Department where [Id]=@DepartmentId);

	INSERT INTO [dbo].[JournalEntry]
	(
		[DocumentNumber],[BranchId],[Date],[SourcePageId],[SourceId],[IsActive],[IsPosted],[IsDeleted],[UserId],[DepartmentId],[CurrencyId],[Equivalent]
	)
	VALUES
	(
		Cast(@JournalEntryDocNum as nvarchar(max)),@BranchId,@VoucherDate,@SourcePageId,@Id,1,0,0,@UserId,@DepartmentId,@CurrencyId,@CurrencyEquivalent
	);

	declare @JournalEntryId int=(select MAX(Id) from [dbo].[JournalEntry]);

	DECLARE @JournalEntryDetail table
	(
		[JournalEntryId] [int] NULL,[Debit] [money] NULL,[Credit] [money] NULL,[CurrencyId] [int] NULL,[Equivalent] [float] NULL,[AccountId] [int] NULL,
		[SourcePageId] [int] NULL,[SourceId] [int] NULL,[IsPosted] [bit] NULL,[IsDeleted] [bit] NULL,[IsActive] [bit] NULL,CostCenterId int null,Notes nvarchar(max)
	);

	Insert into @JournalEntryDetail([JournalEntryId],[Debit],[Credit],[CurrencyId],[Equivalent],[AccountId],[SourcePageId],[SourceId],[IsPosted],[IsDeleted],[IsActive],CostCenterId)
	VALUES
		(@JournalEntryId,ISNULL(@Total,0),0,@CurrencyId,@CurrencyEquivalent,@PurchaseAccountId,@SourcePageId,@Id,0,0,1,@CostCenterId),
		(@JournalEntryId,ISNULL(@SalesTaxes,0),0,@CurrencyId,@CurrencyEquivalent,@DebitValueAddedTaxesAccountId,@SourcePageId,@Id,0,0,1,null),
		(@JournalEntryId,0,ISNULL(@CommercialRevenueTax,0),@CurrencyId,@CurrencyEquivalent,@CommercialRevenueTaxAccountId,@SourcePageId,@Id,0,0,1,null),
		(@JournalEntryId,0,ISNULL(@VoucherDiscountValue,0),@CurrencyId,@CurrencyEquivalent,@AcquiredDeductionAccountId,@SourcePageId,@Id,0,0,1,null);

	declare @PaymentMethodId int,@Amount money,@CashBoxId int,@accountId int,@VendorName nvarchar(max);
	declare PurchaseInvoicePaymentMethodsCur cursor for select PaymentMethodId,Amount,CashBoxId from PurchaseInvoicePaymentMethods where PurchaseInvoiceId=@Id;
	open PurchaseInvoicePaymentMethodsCur;
	fetch next from PurchaseInvoicePaymentMethodsCur into @PaymentMethodId,@Amount,@CashBoxId;
	while @@FETCH_STATUS=0
	begin
		if(@PaymentMethodId=1)
		begin
			set @accountId=(select AccountId from CashBox where Id=@CashBoxId);
			set @VendorName=null;
		end
		else if (@PaymentMethodId=2)
		begin
			set @accountId=@VendorAccountId;
			set @VendorName=(select ArName from Vendor where Id=@VendorOrCustomerId);
		end
		else
		begin
			set @accountId=(select AccountId from PaymentMethod where Id=@PaymentMethodId);
			set @VendorName=null;
		end

		Insert into @JournalEntryDetail([JournalEntryId],[Debit],[Credit],[CurrencyId],[Equivalent],[AccountId],[SourcePageId],[SourceId],[IsPosted],[IsDeleted],[IsActive],CostCenterId,Notes)
		VALUES (@JournalEntryId,0,ISNULL(@Amount,0),@CurrencyId,@CurrencyEquivalent,@accountId,@SourcePageId,@Id,0,0,1,null,@VendorName);

		fetch next from PurchaseInvoicePaymentMethodsCur into @PaymentMethodId,@Amount,@CashBoxId;
	end
	close PurchaseInvoicePaymentMethodsCur;
	deallocate PurchaseInvoicePaymentMethodsCur;

	declare @PurchaseInvoiceDirectExpensesId int,@TotalAmount money,@DirectExpenseAccountId int,@TaxesAmount money,@ExpensesAmount money;
	declare PurchaseInvoiceDirectExpensesCur cursor for select Id from PurchaseInvoiceDirectExpenses where PurchaseInvoiceId=@Id;
	open PurchaseInvoiceDirectExpensesCur;
	fetch next from PurchaseInvoiceDirectExpensesCur into @PurchaseInvoiceDirectExpensesId;
	while @@FETCH_STATUS=0
	begin
		if((select PaymentMethod from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId)=1)
		begin
			set @accountId=(select AccountId from CashBox where Id=(select CashBoxId from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId));
			set @VendorName=null;
		end
		else if ((select PaymentMethod from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId)=2)
		begin
			set @accountId=@VendorAccountId;
			set @VendorName=(select ArName from Vendor where Id=@VendorOrCustomerId);
		end
		else
		begin
			set @accountId=(select AccountId from Employee where Id=(select EmployeeId from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId));
			set @VendorName=null;
		end

		set @ExpensesAmount=(select Amount from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId);
		set @TaxesAmount=(select TaxesAmount from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId);
		set @TotalAmount=@ExpensesAmount+@TaxesAmount;
		set @DirectExpenseAccountId=(select AccountId from DirectExpenses where Id=(select DirectExpensesId from PurchaseInvoiceDirectExpenses where Id=@PurchaseInvoiceDirectExpensesId));

		Insert into @JournalEntryDetail([JournalEntryId],[Debit],[Credit],[CurrencyId],[Equivalent],[AccountId],[SourcePageId],[SourceId],[IsPosted],[IsDeleted],[IsActive],CostCenterId,Notes)
		VALUES
			(@JournalEntryId,ISNULL(@ExpensesAmount,0),0,@CurrencyId,@CurrencyEquivalent,@DirectExpenseAccountId,@SourcePageId,@Id,0,0,1,null,null),
			(@JournalEntryId,ISNULL(@TaxesAmount,0),0,@CurrencyId,@CurrencyEquivalent,@DebitValueAddedTaxesAccountId,@SourcePageId,@Id,0,0,1,null,null),
			(@JournalEntryId,0,ISNULL(@TotalAmount,0),@CurrencyId,@CurrencyEquivalent,@accountId,@SourcePageId,@Id,0,0,1,null,@VendorName),
			(@JournalEntryId,ISNULL(@ExpensesAmount,0),0,@CurrencyId,@CurrencyEquivalent,@PurchaseAccountId,@SourcePageId,@Id,0,0,1,@CostCenterId,null),
			(@JournalEntryId,0,ISNULL(@ExpensesAmount,0),@CurrencyId,@CurrencyEquivalent,@DirectExpenseAccountId,@SourcePageId,@Id,0,0,1,null,null);

		fetch next from PurchaseInvoiceDirectExpensesCur into @PurchaseInvoiceDirectExpensesId;
	end
	close PurchaseInvoiceDirectExpensesCur;
	deallocate PurchaseInvoiceDirectExpensesCur;

	Insert into [dbo].[JournalEntryDetail]
	(
		[JournalEntryId],[Debit],[Credit],[CurrencyId],[Equivalent],[AccountId],[SourcePageId],[SourceId],[IsPosted],[IsDeleted],[IsActive],CostCenterId,Notes
	)
	select [JournalEntryId],[Debit],[Credit],[CurrencyId],[Equivalent],[AccountId],[SourcePageId],[SourceId],[IsPosted],[IsDeleted],[IsActive],CostCenterId,Notes
	from @JournalEntryDetail;

	if @DistributeItems=1
	begin
		declare @DistributeWarehouseId int,@totalCost money;
		declare distCur cursor for SELECT distinct WarehouseId FROM PurchaseInvoiceDetails where MainDocId=@Id;
		open distCur;
		fetch next from distCur into @DistributeWarehouseId;
		while @@FETCH_STATUS=0
		begin
			set @totalCost=(select SUM(CostPrice*Qty) from PurchaseInvoiceDetails where MainDocId=@Id and WareHouseId=@DistributeWarehouseId);
			exec [dbo].[StockReceiptVoucher_Insert] null,@BranchId,@DistributeWarehouseId,@DepartmentId,@VoucherDate,@VendorOrCustomerId,@CurrencyId,@CurrencyEquivalent,0,0,0,0,0,0,0,@Paid,@ValidityPeriod,@DeliveryPeriod,null,@CurrentQuantity,@DestinationWarehouseId,@SourcePageId,@Id,@totalCost,0,@IsDelivered,@IsAccepted,@IsLinked,@IsCompleted,0,@UserId,@IsActive,@IsDeleted,1,@Notes,@Image,@UpdatedId,null,1,@PatchDetails;

			insert into StockReceiptVoucherDetails(MainDocId,ItemId,Qty,Price,CostPrice,ItemDirectExpenses,SystemPageId,SelectedId,IsDeleted)
			SELECT (select MAX(Id) from StockReceiptVoucher),ItemId,Qty,Price,CostPrice,ItemDirectExpenses,@SourcePageId,@Id,0
			FROM PurchaseInvoiceDetails where MainDocId=@Id and WareHouseId=@DistributeWarehouseId;

			fetch next from distCur into @DistributeWarehouseId;
		end
		close distCur;
		deallocate distCur;
	end
	else
	begin
		exec [dbo].[StockReceiptVoucher_Insert] null,@BranchId,@WarehouseId,@DepartmentId,@VoucherDate,@VendorOrCustomerId,@CurrencyId,@CurrencyEquivalent,0,0,0,0,0,0,0,@Paid,@ValidityPeriod,@DeliveryPeriod,null,@CurrentQuantity,@DestinationWarehouseId,@SourcePageId,@Id,@Total,0,@IsDelivered,@IsAccepted,@IsLinked,@IsCompleted,0,@UserId,@IsActive,@IsDeleted,1,@Notes,@Image,@UpdatedId,@Details,1,null;
	end

	declare @ItemId int;
	EXEC sp_xml_preparedocument @SerialNumbersOut OUT, @SerialNumbers;
	INSERT INTO [dbo].[PurchaseSaleSerialNumber]
	(
		[PageSourceId],[SelectedId],[ItemId],[SerialNumber],[IsActive],[IsDeleted]
	)
	SELECT
		@SourcePageId,@Id,[ItemId],[SerialNumber],1,0
	FROM OPENXML (@SerialNumbersOut, '/DocumentElement/SerialNumbers', 2)
	WITH ([PageSourceId] [int],[SelectedId] [int],[ItemId] [int],[SerialNumber] [nvarchar](100),[IsActive] [bit],[IsDeleted] [bit]);
	EXEC sp_xml_removedocument @SerialNumbersOut;

	if @AlterPrices=1
	begin
		DECLARE @AlteredPricesOut int;
		DECLARE @AlteredPricesTable table([ItemId] int,[Price1] money,[Price2] money,[Price3] money);

		EXEC sp_xml_preparedocument @AlteredPricesOut OUT, @AlteredPrices;
		INSERT INTO @AlteredPricesTable([ItemId],[Price1],[Price2],[Price3])
		SELECT [ItemId],[Price1],[Price2],[Price3]
		FROM OPENXML (@AlteredPricesOut, '/DocumentElement/AlteredPrices', 2)
		WITH([ItemId] int,[Price1] money,[Price2] money,[Price3] money);
		EXEC sp_xml_removedocument @AlteredPricesOut;

		declare cur2 cursor for select distinct [ItemId] from @AlteredPricesTable;
		open cur2;
		fetch next from cur2 into @ItemId;
		while @@FETCH_STATUS=0
		begin
			update ItemPrice set Price=(select top 1 [Price1] from @AlteredPricesTable where [ItemId]=@ItemId) where ItemId=@ItemId and CustomerGroupId=1;
			update ItemPrice set Price=(select top 1 [Price2] from @AlteredPricesTable where [ItemId]=@ItemId) where ItemId=@ItemId and CustomerGroupId=2;
			update ItemPrice set Price=(select top 1 [Price3] from @AlteredPricesTable where [ItemId]=@ItemId) where ItemId=@ItemId and CustomerGroupId=3;
			fetch next from cur2 into @ItemId;
		end
		close cur2;
		deallocate cur2;
	end

	if @SystemPageId=58
	begin
		update SalesInvoice set IsLinked=1 where Id=@SelectedId;
	end
lbexit:
if @trancount = 0
commit;
END TRY
BEGIN CATCH
declare @error int,@message varchar(4000),@xstate int;
select @error=ERROR_NUMBER(),@message=ERROR_MESSAGE()+' at '+cast(ERROR_LINE() as VARCHAR(50)),@xstate=XACT_STATE();

	if @xstate=-1 rollback;
	if @xstate=1 and @trancount=0 rollback;
	if @xstate=1 and @trancount>0 rollback transaction PurchaseInvoice_Insert;

	raiserror ('PurchaseInvoice_Insert: %d: %s', 16, 1, @error, @message);
END CATCH
END

