CREATE   PROCEDURE [dbo].[SalesQuotation_Update]
@Id [int],
@DocumentNumber nvarchar,
@BranchId [int],
@WarehouseId [int],
@DepartmentId [int],
@VoucherDate [datetime],
@VendorOrCustomerId [int],
@CurrencyId [int],
@CurrencyEquivalent [float],
@Total [money],
@TotalItemsDiscount [money],
@SalesTaxes [money],
@TotalAfterTaxes [money],
@VoucherDiscountValue [money],
@VoucherDiscountPercentage [float],
@NetTotal [money],
@Paid [money],
@ValidityPeriod [float],
@DeliveryPeriod [float],
@CostPriceId [int],
@CurrentQuantity [float],
@DestinationWarehouseId [int],
@SystemPageId [int],
@SelectedId [int],
@TotalCostPrice [money],
@TotalItemDirectExpenses [money],
@IsDelivered [bit],
@IsAccepted [bit],
@IsLinked [bit],
@IsCompleted [bit],
@IsPosted [bit],
@UserId [int],
@IsActive [bit],
@IsDeleted [bit],
@AutoCreated [bit],
@CostPriceChecked [bit],
@Notes nvarchar,
@Image nvarchar,
@UpdatedId [int],
@Details NTEXT,
@CustomerRepId [int]
AS
BEGIN TRAN
SET NOCOUNT ON;

DECLARE @DetailsOut int;
DECLARE @OldMoneyTotal money=(select [NetTotal] from [dbo].[SalesQuotation] where [Id]=@Id);

UPDATE [dbo].[SalesQuotation]
SET [DocumentNumber] = @DocumentNumber,
	[BranchId] = @BranchId,
	[WarehouseId] = @WarehouseId,
	[DepartmentId] = @DepartmentId,
	[VoucherDate] = @VoucherDate,
	[VendorOrCustomerId] = @VendorOrCustomerId,
	[CurrencyId] = @CurrencyId,
	[CurrencyEquivalent] = @CurrencyEquivalent,
	[Total] = @Total,
	[TotalItemsDiscount] = @TotalItemsDiscount,
	[SalesTaxes] = @SalesTaxes,
	[TotalAfterTaxes] = @TotalAfterTaxes,
	[VoucherDiscountValue] = @VoucherDiscountValue,
	[VoucherDiscountPercentage] = @VoucherDiscountPercentage,
	[NetTotal] = @NetTotal,
	[Paid] = @Paid,
	[ValidityPeriod] = @ValidityPeriod,
	[DeliveryPeriod] = @DeliveryPeriod,
	[CostPriceId] = @CostPriceId,
	[CurrentQuantity] = @CurrentQuantity,
	[DestinationWarehouseId] = @DestinationWarehouseId,
	[SystemPageId] = @SystemPageId,
	[SelectedId] = @SelectedId,
	[TotalCostPrice] = @TotalCostPrice,
	[TotalItemDirectExpenses] = @TotalItemDirectExpenses,
	[IsDelivered] = @IsDelivered,
	[IsAccepted] = @IsAccepted,
	[IsLinked] = @IsLinked,
	[IsCompleted] = @IsCompleted,
	[IsPosted] = 0,
	[UserId] = @UserId,
	[IsActive] = @IsActive,
	[IsDeleted] = @IsDeleted,
	[AutoCreated] = @AutoCreated,
	[CostPriceChecked]=@CostPriceChecked,
	[Notes] = @Notes,
	[Image] = @Image,
	[UpdatedId] = @UpdatedId,
	[CustomerRepId] = @CustomerRepId
WHERE [Id]=@Id;

DECLARE @MainDocId int=@Id;
DELETE FROM [SalesQuotationDetails] WHERE [MainDocId]=@MainDocId;

EXEC sp_xml_preparedocument @DetailsOut OUT, @Details;
INSERT INTO [dbo].[SalesQuotationDetails]
(
	[MainDocId],[ItemId],[Qty],[ItemPriceId],[Price],[ItemUnitId],[UnitEquivalent],[CurrencyId],[CurrencyEquivalent],
	[DiscountValue],[DiscountPerc],[WareHouseId],[WarrantyPeriod],[WarrantyStart],[ExpireDate],[PatchId],[SystemPageId],[SelectedId],
	[RemainQty],[CostPrice],[ItemDirectExpenses],[IsDeleted],[UpdatedId],[Notes],[Width],[Height],[Area],
	CarTypeId,CarModelId,CarColorId,ChassisNo,EngineNo,ManufacturingYear,PlateNo,VehicleNotes,VehicleStockId
)
SELECT
	@MainDocId,[ItemId],[Qty],[ItemPriceId],[Price],[ItemUnitId],[UnitEquivalent],[CurrencyId],[CurrencyEquivalent],
	[DiscountValue],[DiscountPerc],[WareHouseId],[WarrantyPeriod],[WarrantyStart],[ExpireDate],[PatchId],[SystemPageId],[SelectedId],
	[RemainQty],[CostPrice],[ItemDirectExpenses],[IsDeleted],[UpdatedId],[Notes],[Width],[Height],[Area],
	NULLIF(CarTypeId,0),
	NULLIF(CarModelId,0),
	NULLIF(CarColorId,0),
	NULLIF(LTRIM(RTRIM(ChassisNo)),''),
	NULLIF(LTRIM(RTRIM(EngineNo)),''),
	NULLIF(ManufacturingYear,0),
	NULLIF(LTRIM(RTRIM(PlateNo)),''),
	NULLIF(LTRIM(RTRIM(VehicleNotes)),''),
	NULLIF(VehicleStockId,0)
FROM OPENXML (@DetailsOut, '/DocumentElement/Details', 2)
WITH
(
	[MainDocId] [int],[ItemId] [int],[Qty] [float],[ItemPriceId] [int],[Price] [money],[ItemUnitId] [int],[UnitEquivalent] [float],
	[CurrencyId] [int],[CurrencyEquivalent] [float],[DiscountValue] [money],[DiscountPerc] [float],[WareHouseId] [int],
	[WarrantyPeriod] [float],[WarrantyStart] [datetime],[ExpireDate] [datetime],[PatchId] [int],[SystemPageId] [int],[SelectedId] [int],
	[RemainQty] [float],[CostPrice] [money],[ItemDirectExpenses] [money],[IsDeleted] [bit],[UpdatedId] [int],[Notes] nvarchar(MAX),
	[Width] float,[Height] float,[Area] float,
	CarTypeId int,CarModelId int,CarColorId int,ChassisNo nvarchar(100),EngineNo nvarchar(100),
	ManufacturingYear int,PlateNo nvarchar(50),VehicleNotes nvarchar(500),VehicleStockId int
);
EXEC sp_xml_removedocument @DetailsOut;

IF OBJECT_ID('dbo.VehicleStock','U') IS NOT NULL
BEGIN
	IF EXISTS
	(
		SELECT 1
		FROM dbo.SalesQuotationDetails d
		WHERE d.MainDocId = @Id
		  AND d.IsDeleted = 0
		  AND d.VehicleStockId IS NOT NULL
		  AND NOT EXISTS
		  (
			  SELECT 1
			  FROM dbo.VehicleStock vs
			  WHERE vs.Id = d.VehicleStockId
				AND vs.IsDeleted = 0
		  )
	)
	BEGIN
		ROLLBACK TRAN;
		RAISERROR('Invalid VehicleStockId selected in SalesQuotation details.',16,1);
		RETURN;
	END
END

IF @@ERROR <> 0
BEGIN
	ROLLBACK TRAN;
	RETURN;
END
ELSE
BEGIN
	COMMIT TRAN;
END

CREATE PROCEDURE dbo.sp_alterdiagram
(
	@diagramname 	sysname,
	@owner_id	int	= null,
	@version 	int,
	@definition 	varbinary(max)
)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on

	declare @theId 			int
	declare @retval 		int
	declare @IsDbo 			int

	declare @UIDFound 		int
	declare @DiagId			int
	declare @ShouldChangeUID	int

	if(@diagramname is null)
	begin
		RAISERROR ('Invalid ARG', 16, 1)
		return -1
	end

	execute as caller;
	select @theId = DATABASE_PRINCIPAL_ID();	 
	select @IsDbo = IS_MEMBER(N'db_owner'); 
	if(@owner_id is null)
		select @owner_id = @theId;
	revert;

	select @ShouldChangeUID = 0
	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 

	if(@DiagId IS NULL or (@IsDbo = 0 and @theId <> @UIDFound))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
		return -3
	end

	if(@IsDbo <> 0)
	begin
		if(@UIDFound is null or USER_NAME(@UIDFound) is null) -- invalid principal_id
		begin
			select @ShouldChangeUID = 1 ;
		end
	end

	-- update dds data			
	update dbo.sysdiagrams set definition = @definition where diagram_id = @DiagId ;

	-- change owner
	if(@ShouldChangeUID = 1)
		update dbo.sysdiagrams set principal_id = @theId where diagram_id = @DiagId ;

	-- update dds version
	if(@version is not null)
		update dbo.sysdiagrams set version = @version where diagram_id = @DiagId ;

	return 0
END

CREATE PROCEDURE dbo.sp_creatediagram
(
	@diagramname 	sysname,
	@owner_id		int	= null, 	
	@version 		int,
	@definition 	varbinary(max)
)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on

	declare @theId int
	declare @retval int
	declare @IsDbo	int
	declare @userName sysname
	if(@version is null or @diagramname is null)
	begin
		RAISERROR (N'E_INVALIDARG', 16, 1);
		return -1
	end

	execute as caller;
	select @theId = DATABASE_PRINCIPAL_ID(); 
	select @IsDbo = IS_MEMBER(N'db_owner');
	revert; 

	if @owner_id is null
	begin
		select @owner_id = @theId;
	end
	else
	begin
		if @theId <> @owner_id
		begin
			if @IsDbo = 0
			begin
				RAISERROR (N'E_INVALIDARG', 16, 1);
				return -1
			end
			select @theId = @owner_id
		end
	end
	-- next 2 line only for test, will be removed after define name unique
	if EXISTS(select diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @diagramname)
	begin
		RAISERROR ('The name is already used.', 16, 1);
		return -2
	end

	insert into dbo.sysdiagrams(name, principal_id , version, definition)
			VALUES(@diagramname, @theId, @version, @definition) ;

	select @retval = @@IDENTITY 
	return @retval
END

CREATE PROCEDURE dbo.sp_dropdiagram
(
	@diagramname 	sysname,
	@owner_id	int	= null
)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on
	declare @theId 			int
	declare @IsDbo 			int

	declare @UIDFound 		int
	declare @DiagId			int

	if(@diagramname is null)
	begin
		RAISERROR ('Invalid value', 16, 1);
		return -1
	end

	EXECUTE AS CALLER;
	select @theId = DATABASE_PRINCIPAL_ID();
	select @IsDbo = IS_MEMBER(N'db_owner'); 
	if(@owner_id is null)
		select @owner_id = @theId;
	REVERT; 

	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
	if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1)
		return -3
	end

	delete from dbo.sysdiagrams where diagram_id = @DiagId;

	return 0;
END

CREATE PROCEDURE dbo.sp_helpdiagramdefinition
(
	@diagramname 	sysname,
	@owner_id	int	= null 		
)
WITH EXECUTE AS N'dbo'
AS
BEGIN
	set nocount on

	declare @theId 		int
	declare @IsDbo 		int
	declare @DiagId		int
	declare @UIDFound	int

	if(@diagramname is null)
	begin
		RAISERROR (N'E_INVALIDARG', 16, 1);
		return -1
	end

	execute as caller;
	select @theId = DATABASE_PRINCIPAL_ID();
	select @IsDbo = IS_MEMBER(N'db_owner');
	if(@owner_id is null)
		select @owner_id = @theId;
	revert; 

	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname;
	if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId ))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1);
		return -3
	end

	select version, definition FROM dbo.sysdiagrams where diagram_id = @DiagId ; 
	return 0
END

CREATE PROCEDURE dbo.sp_renamediagram
(
	@diagramname 		sysname,
	@owner_id		int	= null,
	@new_diagramname	sysname

)
WITH EXECUTE AS 'dbo'
AS
BEGIN
	set nocount on
	declare @theId 			int
	declare @IsDbo 			int

	declare @UIDFound 		int
	declare @DiagId			int
	declare @DiagIdTarg		int
	declare @u_name			sysname
	if((@diagramname is null) or (@new_diagramname is null))
	begin
		RAISERROR ('Invalid value', 16, 1);
		return -1
	end

	EXECUTE AS CALLER;
	select @theId = DATABASE_PRINCIPAL_ID();
	select @IsDbo = IS_MEMBER(N'db_owner'); 
	if(@owner_id is null)
		select @owner_id = @theId;
	REVERT;

	select @u_name = USER_NAME(@owner_id)

	select @DiagId = diagram_id, @UIDFound = principal_id from dbo.sysdiagrams where principal_id = @owner_id and name = @diagramname 
	if(@DiagId IS NULL or (@IsDbo = 0 and @UIDFound <> @theId))
	begin
		RAISERROR ('Diagram does not exist or you do not have permission.', 16, 1)
		return -3
	end

	-- if((@u_name is not null) and (@new_diagramname = @diagramname))	-- nothing will change
	--	return 0;

	if(@u_name is null)
		select @DiagIdTarg = diagram_id from dbo.sysdiagrams where principal_id = @theId and name = @new_diagramname
	else
		select @DiagIdTarg = diagram_id from dbo.sysdiagrams where principal_id = @owner_id and name = @new_diagramname

	if((@DiagIdTarg is not null) and  @DiagId <> @DiagIdTarg)
	begin
		RAISERROR ('The name is already used.', 16, 1);
		return -2
	end		

	if(@u_name is null)
		update dbo.sysdiagrams set [name] = @new_diagramname, principal_id = @theId where diagram_id = @DiagId
	else
		update dbo.sysdiagrams set [name] = @new_diagramname where diagram_id = @DiagId
	return 0
END

