	@UpdatedId [int],
	@Details NTEXT
AS
BEGIN TRAN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	DECLARE @DetailsOut int
	DECLARE @DocumentNumber int =  isnull((select top(1) convert (int,[DocumentNumber]) from [StockLossesVoucher] where [DepartmentId]=@DepartmentId order by [Id] desc),0)+1

INSERT INTO [dbo].[StockLossesVoucher]
