           ,[TotalItemDirectExpenses]
           ,[IsDelivered]
           ,[IsAccepted]
           ,[IsLinked]
           ,[IsCompleted]
           ,[IsPosted]
           ,[UserId]
           ,[IsActive]
           ,[IsDeleted]
           ,[AutoCreated]
           ,[Notes]
           ,[Image]
           ,[UpdatedId])
VALUES(cast (@DocumentNumber as nvarchar(max))   ,
	@BranchId ,
	@WarehouseId  ,
	@DepartmentId  ,
	@VoucherDate  ,
	@VendorOrCustomerId  ,
	@CurrencyId  ,
	@CurrencyEquivalent ,
	@Total  ,
	@TotalItemsDiscount  ,
	@SalesTaxes  ,
	@TotalAfterTaxes  ,
	@VoucherDiscountValue  ,
	@VoucherDiscountPercentage  ,
	@NetTotal  ,
	@Paid  ,
	@ValidityPeriod  ,
	@DeliveryPeriod  ,
	@CostPriceId  ,
	@CurrentQuantity  ,
	@DestinationWarehouseId  ,
	@SystemPageId  ,
	@SelectedId  ,
	@TotalCostPrice  ,
	@TotalItemDirectExpenses  ,
	@IsDelivered  ,
	@IsAccepted  ,
	@IsLinked  ,
	@IsCompleted  ,
	0  ,
	@UserId  ,
	@IsActive  ,
	@IsDeleted  ,
	@AutoCreated  ,
	@Notes  ,
	@Image  ,
	@UpdatedId)

DECLARE @Id int=(select MAX([Id]) from [StockLossesVoucher])

EXEC sp_xml_preparedocument @DetailsOut OUT, @Details
INSERT INTO [dbo].[StockLossesVoucherDetails]
           ([MainDocId]
           ,[ItemId]
           ,[Qty]
           ,[ItemPriceId]
           ,[Price]
           ,[ItemUnitId]
