           ,[ItemPriceId]
           ,[Price]
           ,[ItemUnitId]
           ,[UnitEquivalent]
           ,[CurrencyId]
           ,[CurrencyEquivalent]
           ,[DiscountValue]
           ,[DiscountPerc]
