           ,[WarrantyPeriod]
           ,[WarrantyStart]
           ,[ExpireDate]
           ,[PatchId]
           ,@SystemPageId
           ,@SelectedId
           ,[RemainQty]
           ,[CostPrice]
           ,[ItemDirectExpenses]
           ,[IsDeleted]
           ,[UpdatedId]
FROM OPENXML (@DetailsOut, '/DocumentElement/Details', 2)
with([MainDocId] [int] ,
	[ItemId] [int] ,
	[Qty] [float] ,
	[ItemPriceId] [int] ,
	[Price] [money] ,
	[ItemUnitId] [int] ,
