	[ExpireDate] [datetime] ,
	[PatchId] [int] ,
	[SystemPageId] [int] ,
	[SelectedId] [int] ,
	[RemainQty] [float] ,
	[CostPrice] [money] ,
	[ItemDirectExpenses] [money] ,
	[IsDeleted] [bit] ,
	[UpdatedId] [int])
EXEC sp_xml_removedocument @DetailsOut

if @@error <>0
begin
rollback tran 
return 
end
else
begin
commit tran
end

